const QUESTIONS = [{"id": "2012-Q1", "year": 2012, "n": 1, "topic": "Operations", "subs": ["Influences", "Operations strategies"], "img": "2012_Q1.png", "w": 1023, "h": 360, "ans": ["D"], "expl": "Outsourcing is using an external provider to perform a business activity (here, cleaning) rather than doing it in-house. Contracting alone isn't the syllabus term \u2014 outsourcing specifically refers to shifting a function to an outside specialist."}, {"id": "2012-Q2", "year": 2012, "n": 2, "topic": "Operations", "subs": ["Operations processes"], "img": "2012_Q2.png", "w": 865, "h": 360, "ans": ["C"], "expl": "Sequencing is deciding the ORDER in which tasks are done; scheduling is deciding WHEN (times/dates). Since the manager is choosing the best order, it's sequencing."}, {"id": "2012-Q3", "year": 2012, "n": 3, "topic": "Marketing", "subs": ["Marketing process"], "img": "2012_Q3.png", "w": 1028, "h": 316, "ans": ["A"], "expl": "Free samples encourage trial of a new product, which suits the establishment (introduction) stage \u2014 the goal is to create awareness and get first-time users."}, {"id": "2012-Q4", "year": 2012, "n": 4, "topic": "Operations", "subs": [], "img": "2012_Q4.png", "w": 876, "h": 299, "ans": ["B"], "expl": "The operations process flows inputs \u2192 transformation \u2192 outputs: materials (input) are transformed by design into a product (output). The other options mix unrelated elements or reverse the flow."}, {"id": "2012-Q5", "year": 2012, "n": 5, "topic": "Human Resources", "subs": ["Key influences"], "img": "2012_Q5.png", "w": 802, "h": 298, "ans": ["C"], "expl": "All Australian employees are legally entitled to minimum employment standards (e.g. the National Employment Standards). Annual wage rises and new contracts every two years are not guaranteed entitlements."}, {"id": "2012-Q6", "year": 2012, "n": 6, "topic": "Marketing", "subs": ["Marketing strategies", "Role of marketing"], "img": "2012_Q6.png", "w": 1028, "h": 391, "ans": ["D"], "expl": "A selling approach focuses on making the product first, then using promotion/advertising to persuade customers to buy it \u2014 exactly what happened here. A marketing approach would start with customer needs."}, {"id": "2012-Q7", "year": 2012, "n": 7, "topic": "Operations", "subs": ["Operations processes"], "img": "2012_Q7.png", "w": 963, "h": 360, "ans": ["A"], "expl": "Demand for lifeguards falls in winter, so fewer are employed \u2014 this is variation (seasonal fluctuation) in demand influencing the transformation process (the 4 V's: volume, variety, variation in demand, visibility)."}, {"id": "2012-Q8", "year": 2012, "n": 8, "topic": "Finance", "subs": ["Processes of financial management"], "img": "2012_Q8.png", "w": 882, "h": 255, "ans": ["A"], "expl": "Gross profit = sales \u2212 cost of goods sold. Cost centres help monitor and control direct costs like COGS, lifting gross profit. Reducing fixed costs or expenses improves NET profit, not gross profit."}, {"id": "2012-Q9", "year": 2012, "n": 9, "topic": "Human Resources", "subs": [], "img": "2012_Q9.png", "w": 1022, "h": 734, "ans": ["B"], "expl": "Best employee relations shows in low staff turnover, high output and low absenteeism. Company B has the lowest turnover (11%), highest output (12) and lowest absenteeism (8)."}, {"id": "2012-Q10", "year": 2012, "n": 10, "topic": "Human Resources", "subs": ["Human resource strategies"], "img": "2012_Q10.png", "w": 1028, "h": 391, "ans": ["C"], "expl": "Performance management is the process of setting employee goals and providing feedback on their achievement \u2014 exactly Sam's job. Recruitment is attracting applicants; job design is structuring roles."}, {"id": "2012-Q11", "year": 2012, "n": 11, "topic": "Operations", "subs": ["Operations strategies"], "img": "2012_Q11.png", "w": 706, "h": 254, "ans": ["C"], "expl": "Logistics covers the physical flow of goods: transport, storage/warehousing, distribution, and materials handling and packaging. Skills audits and budgets belong to HR and finance."}, {"id": "2012-Q12", "year": 2012, "n": 12, "topic": "Human Resources", "subs": ["Human resource strategies"], "img": "2012_Q12.png", "w": 1028, "h": 391, "ans": ["B"], "expl": "A democratic (participative) leadership style involves employees in decision-making and values their input. Autocratic is directive; laissez-faire leaves employees alone."}, {"id": "2012-Q13", "year": 2012, "n": 13, "topic": "Human Resources", "subs": ["Human resource strategies"], "img": "2012_Q13.png", "w": 1028, "h": 422, "ans": ["D"], "expl": "Following the formal complaint process set out in workplace policy (written complaint to management/HR) is applying grievance procedures \u2014 the established steps for resolving complaints internally."}, {"id": "2012-Q14", "year": 2012, "n": 14, "topic": "Operations", "subs": ["Operations processes", "Operations strategies"], "img": "2012_Q14.png", "w": 953, "h": 763, "ans": ["C"], "expl": "The critical path is the LONGEST route through the network, which sets the minimum completion time. Adding the longest chain of dependent tasks gives 17 days."}, {"id": "2012-Q15", "year": 2012, "n": 15, "topic": "Marketing", "subs": ["Marketing process", "Marketing strategies"], "img": "2012_Q15.png", "w": 772, "h": 360, "ans": ["D"], "expl": "Fitness-conscious = lifestyle/values = psychographic; office workers = occupation = demographic. Geographic is location; behavioural is usage/loyalty patterns."}, {"id": "2012-Q16", "year": 2012, "n": 16, "topic": "Operations", "subs": ["Influences"], "img": "2012_Q16.png", "w": 1028, "h": 391, "ans": ["A"], "expl": "The GFC was a downturn in the economic cycle \u2014 an economic influence on HR that forced businesses to shed staff. 'Financial' refers to a business function, not an external influence category."}, {"id": "2012-Q17", "year": 2012, "n": 17, "topic": "Marketing", "subs": ["Marketing strategies"], "img": "2012_Q17.png", "w": 1028, "h": 347, "ans": ["A"], "expl": "A loss leader is priced at or below cost to lure customers in, expecting them to buy other profitable items \u2014 the 20-cent drink does exactly this. Penetration pricing is a low INTRODUCTORY price for a new product."}, {"id": "2012-Q18", "year": 2012, "n": 18, "topic": "Marketing", "subs": [], "img": "2012_Q18.png", "w": 1028, "h": 944, "ans": ["D"], "expl": "The objective was to take market share from competitors. In Country D, Star Car's market share fell most (10% \u2192 6%) and sales fell, so the objective was least effective there."}, {"id": "2012-Q19", "year": 2012, "n": 19, "topic": "Marketing", "subs": [], "img": "2012_Q19.png", "w": 1028, "h": 850, "ans": ["D"], "expl": "In Country C, Star Car's sales stayed at $10m while its share fell from 10% to 8% \u2014 the only way share falls with constant sales (and constant prices) is if the total market grew. So C: market up, share down."}, {"id": "2012-Q20", "year": 2012, "n": 20, "topic": "Finance", "subs": ["Influences on financial management"], "img": "2012_Q20.png", "w": 1028, "h": 285, "ans": ["B"], "expl": "A higher AUD makes Australian exports more expensive for foreign buyers. Wine producers exporting to NZ lose sales/competitiveness. Importers (car makers buying from Italy) actually benefit from a higher dollar."}, {"id": "2013-Q1", "year": 2013, "n": 1, "topic": "Marketing", "subs": [], "img": "2013_Q1.png", "w": 1029, "h": 329, "ans": ["D"], "expl": "Operations is the business function that transforms inputs (raw materials, resources) into outputs (finished goods and services). That transformation is its defining role."}, {"id": "2013-Q2", "year": 2013, "n": 2, "topic": "Marketing", "subs": [], "img": "2013_Q2.png", "w": 972, "h": 359, "ans": ["B"], "expl": "Toy stores buy the bears to resell them \u2014 buyers who purchase to resell make up the intermediate market. Consumers buy for personal use; resource markets involve raw materials."}, {"id": "2013-Q3", "year": 2013, "n": 3, "topic": "Human Resources", "subs": ["Human resource strategies", "Processes of human resource management"], "img": "2013_Q3.png", "w": 824, "h": 344, "ans": ["C"], "expl": "Recruitment is the process of attracting a pool of applicants, which includes advertising vacancies. Selection is choosing among applicants \u2014 that comes after."}, {"id": "2013-Q4", "year": 2013, "n": 4, "topic": "Finance", "subs": ["Processes of financial management", "Role of financial management"], "img": "2013_Q4.png", "w": 500, "h": 255, "ans": ["A"], "expl": "The expense ratio (total expenses \u00f7 sales) measures efficiency \u2014 how well the business controls its costs relative to sales. Profitability ratios involve profit figures; solvency involves gearing."}, {"id": "2013-Q5", "year": 2013, "n": 5, "topic": "Operations", "subs": ["Influences", "Operations strategies"], "img": "2013_Q5.png", "w": 1029, "h": 345, "ans": ["A"], "expl": "Buying from the cheapest suppliers anywhere in the world, regardless of location, is global sourcing. Economies of scale relate to production volume; global branding is a marketing strategy."}, {"id": "2013-Q6", "year": 2013, "n": 6, "topic": "Finance", "subs": ["Processes of financial management"], "img": "2013_Q6.png", "w": 1017, "h": 299, "ans": ["B"], "expl": "Sale and lease-back converts a fixed (non-current) asset into cash immediately, boosting current assets and therefore working capital. Repaying creditors faster reduces cash; credit sales don't bring in cash immediately."}, {"id": "2013-Q7", "year": 2013, "n": 7, "topic": "Finance", "subs": ["Influences on financial management", "Processes of financial management"], "img": "2013_Q7.png", "w": 1029, "h": 297, "ans": ["D"], "expl": "Opportunities and threats are EXTERNAL factors. Strong economic growth (opportunity) and increased tax rates (threat) are both external. The other options include internal strengths/weaknesses like loyal employees or high gearing."}, {"id": "2013-Q8", "year": 2013, "n": 8, "topic": "Operations", "subs": ["Operations processes", "Operations strategies"], "img": "2013_Q8.png", "w": 789, "h": 291, "ans": ["D"], "expl": "The critical path is the sequence of dependent tasks with no slack \u2014 it shows the shortest time in which ALL tasks of the project can be completed. Any delay on it delays the whole project."}, {"id": "2013-Q9", "year": 2013, "n": 9, "topic": "Marketing", "subs": ["Marketing process", "Marketing strategies"], "img": "2013_Q9.png", "w": 878, "h": 250, "ans": ["C"], "expl": "Price skimming sets a high initial price to maximise profit while demand is strong and competition is limited (e.g. new technology). Achieving market share quickly is penetration pricing \u2014 the opposite."}, {"id": "2013-Q10", "year": 2013, "n": 10, "topic": "Finance", "subs": ["Processes of financial management"], "img": "2013_Q10.png", "w": 896, "h": 299, "ans": ["D"], "expl": "A higher current ratio means better liquidity, and a higher accounts receivable turnover means debts are collected faster \u2014 both improve the financial position."}, {"id": "2013-Q11", "year": 2013, "n": 11, "topic": "Marketing", "subs": ["Marketing strategies"], "img": "2013_Q11.png", "w": 1029, "h": 391, "ans": ["B"], "expl": "Sugging is 'selling under the guise' of market research \u2014 pretending to survey someone, then selling to them. It is not illegal in Australia, but it is widely considered unethical."}, {"id": "2013-Q12", "year": 2013, "n": 12, "topic": "Marketing", "subs": ["Marketing strategies"], "img": "2013_Q12.png", "w": 1029, "h": 391, "ans": ["C"], "expl": "Positioning is creating a distinct image of the product in consumers' minds relative to competitors ('more exciting and fun than competitors' cars'). Personal selling and PR are promotion methods, not image-building comparisons."}, {"id": "2013-Q13", "year": 2013, "n": 13, "topic": "Human Resources", "subs": ["Key influences"], "img": "2013_Q13.png", "w": 1029, "h": 347, "ans": ["C"], "expl": "Four weeks annual leave is one of the National Employment Standards (NES) under the Fair Work Act \u2014 the legal minimum for permanent employees. Awards and common law build on top of the NES."}, {"id": "2013-Q14", "year": 2013, "n": 14, "topic": "Operations", "subs": ["Influences", "Operations processes"], "img": "2013_Q14.png", "w": 882, "h": 299, "ans": ["D"], "expl": "Transforming resources carry OUT the transformation: human resources and facilities. Transformed resources are changed BY the process: materials, information and customers."}, {"id": "2013-Q15", "year": 2013, "n": 15, "topic": "Marketing", "subs": ["Marketing strategies"], "img": "2013_Q15.png", "w": 819, "h": 360, "ans": ["A"], "expl": "Spending most of the marketing budget on advertising reflects a selling approach \u2014 pushing the product onto customers through heavy promotion, rather than starting from customer needs (marketing approach)."}, {"id": "2013-Q16", "year": 2013, "n": 16, "topic": "Finance", "subs": [], "img": "2013_Q16.png", "w": 1029, "h": 390, "ans": ["A"], "expl": "Recording an expense (legal fees) as part of an asset's value is capitalising expenses \u2014 it overstates assets and understates expenses, a recognised limitation of financial reports."}, {"id": "2013-Q17", "year": 2013, "n": 17, "topic": "Operations", "subs": ["Operations processes"], "img": "2013_Q17.png", "w": 1029, "h": 249, "ans": ["B"], "expl": "Lowest unit costs come from standardisation: little customer contact, low variety and HIGH volume, which maximises economies of scale. High variety and contact raise costs; low volume spreads fixed costs over fewer units."}, {"id": "2013-Q18", "year": 2013, "n": 18, "topic": "Finance", "subs": [], "img": "2013_Q18.png", "w": 1029, "h": 384, "ans": ["A"], "expl": "With rising stock costs, FIFO values cost of goods sold at the OLDER, cheaper prices, giving lower COGS and therefore higher reported profit for the current period. LIFO would do the opposite."}, {"id": "2013-Q19", "year": 2013, "n": 19, "topic": "Marketing", "subs": [], "img": "2013_Q19.png", "w": 993, "h": 947, "ans": ["D"], "expl": "Region C was the most successful region (only one to exceed its planned sales: 1,000,000 actual vs 800,000 planned). Within it, Salesperson 8 had the highest variance (+50%), making D correct."}, {"id": "2013-Q20", "year": 2013, "n": 20, "topic": "Human Resources", "subs": ["Human resource strategies", "Processes of human resource management"], "img": "2013_Q20.png", "w": 980, "h": 254, "ans": ["C"], "expl": "Developmental performance management focuses on improving an INDIVIDUAL employee's skills and career growth (e.g. leadership skills). Administrative performance management collects data for organisational decisions."}, {"id": "2014-Q1", "year": 2014, "n": 1, "topic": "Marketing", "subs": ["Influences on marketing"], "img": "2014_Q1.png", "w": 967, "h": 360, "ans": ["C"], "expl": "Sally's choice is driven by her personal perception and past experience of service \u2014 a psychological factor. Sociocultural factors are influences from family, peers and culture."}, {"id": "2014-Q2", "year": 2014, "n": 2, "topic": "Finance", "subs": ["Role of financial management"], "img": "2014_Q2.png", "w": 958, "h": 360, "ans": ["A"], "expl": "Increasing market share by merging is expansion \u2014 the financial objective of growth. Liquidity is meeting short-term debts; solvency long-term; profitability is maximising returns."}, {"id": "2014-Q3", "year": 2014, "n": 3, "topic": "Human Resources", "subs": ["Key influences"], "img": "2014_Q3.png", "w": 863, "h": 316, "ans": ["C"], "expl": "Independent contractors are not employees: they pay their own tax and don't receive award conditions or paid leave from the client. That's why only the income tax statement is true."}, {"id": "2014-Q4", "year": 2014, "n": 4, "topic": "Human Resources", "subs": ["Human resource strategies"], "img": "2014_Q4.png", "w": 522, "h": 299, "ans": ["B"], "expl": "Grievance procedures are the formal steps for handling employee COMPLAINTS about treatment at work. Illness is handled by leave; appraisal by performance management."}, {"id": "2014-Q5", "year": 2014, "n": 5, "topic": "Operations", "subs": ["Operations strategies"], "img": "2014_Q5.png", "w": 933, "h": 298, "ans": ["B"], "expl": "The operations performance objectives are quality, speed, dependability, flexibility, customisation and cost. Option B lists four of them. Profit and choice are not performance objectives."}, {"id": "2014-Q6", "year": 2014, "n": 6, "topic": "Marketing", "subs": ["Marketing process"], "img": "2014_Q6.png", "w": 1028, "h": 391, "ans": ["C"], "expl": "Rapid sales increase for a NEW business signals moving out of establishment (slow initial sales) into the growth stage \u2014 the steepest part of the product life cycle curve."}, {"id": "2014-Q7", "year": 2014, "n": 7, "topic": "Operations", "subs": ["Operations strategies"], "img": "2014_Q7.png", "w": 1028, "h": 377, "ans": ["B"], "expl": "Just-in-time holds no buffer stock \u2014 inputs arrive only as needed, so one late tyre delivery stops the whole assembly line. Just-in-case would have held safety stock."}, {"id": "2014-Q8", "year": 2014, "n": 8, "topic": "Marketing", "subs": ["Marketing strategies"], "img": "2014_Q8.png", "w": 941, "h": 360, "ans": ["C"], "expl": "Selective distribution uses fewer, chosen outlets, which supports an image of higher quality/exclusivity \u2014 repositioning the product upmarket. Intensive distribution suits mass-market convenience goods."}, {"id": "2014-Q9", "year": 2014, "n": 9, "topic": "Marketing", "subs": ["Marketing strategies"], "img": "2014_Q9.png", "w": 788, "h": 298, "ans": ["B"], "expl": "Penetration pricing sets a low initial price to win market share quickly. Skimming maximises profit per unit; quality reputations come from premium pricing."}, {"id": "2014-Q10", "year": 2014, "n": 10, "topic": "Finance", "subs": ["Processes of financial management"], "img": "2014_Q10.png", "w": 786, "h": 298, "ans": ["B"], "expl": "The income statement shows revenue, cost of goods sold, gross profit, expenses and net profit. Accounts payable, intangibles and net assets appear on the balance sheet."}, {"id": "2014-Q11", "year": 2014, "n": 11, "topic": "Marketing", "subs": ["Marketing strategies"], "img": "2014_Q11.png", "w": 1028, "h": 347, "ans": ["C"], "expl": "Same brand sold in both countries = global branding; different recipe adapted to Chinese tastes = customisation. Standardisation would mean an identical product everywhere."}, {"id": "2014-Q12", "year": 2014, "n": 12, "topic": "Human Resources", "subs": ["Key influences"], "img": "2014_Q12.png", "w": 771, "h": 360, "ans": ["D"], "expl": "Changed work patterns include MORE casualisation, part-time work and female participation \u2014 the decline has been in full-time male participation."}, {"id": "2014-Q13", "year": 2014, "n": 13, "topic": "Human Resources", "subs": ["Human resource strategies"], "img": "2014_Q13.png", "w": 822, "h": 298, "ans": ["B"], "expl": "Democratic leadership works best with experienced, skilled employees who can contribute meaningfully to decisions. Tight deadlines, standardisation and danger favour autocratic styles."}, {"id": "2014-Q14", "year": 2014, "n": 14, "topic": "Finance", "subs": ["Processes of financial management"], "img": "2014_Q14.png", "w": 789, "h": 298, "ans": ["C"], "expl": "Debentures are debt finance \u2014 lenders get interest but no ownership or voting rights, so existing owners retain control. Issuing shares would dilute ownership."}, {"id": "2014-Q15", "year": 2014, "n": 15, "topic": "Operations", "subs": ["Operations strategies"], "img": "2014_Q15.png", "w": 881, "h": 298, "ans": ["C"], "expl": "Economies of scale mean lower average (per-unit) costs as output rises \u2014 i.e. greater production efficiency. Option D says the opposite; flexibility usually falls with scale."}, {"id": "2014-Q16", "year": 2014, "n": 16, "topic": "Human Resources", "subs": ["Processes of human resource management"], "img": "2014_Q16.png", "w": 804, "h": 254, "ans": ["D"], "expl": "In a recession unemployment rises, so workers have less bargaining power \u2014 employers can hire from a larger labour pool. Wages and overtime typically fall, and involuntary separations increase."}, {"id": "2014-Q17", "year": 2014, "n": 17, "topic": "Human Resources", "subs": [], "img": "2014_Q17.png", "w": 908, "h": 299, "ans": ["A"], "expl": "Legal compliance means meeting legal obligations \u2014 paying taxes on time. Offsetting carbon emissions is voluntary CSR; induction and dividends are not legal requirements in this sense."}, {"id": "2014-Q18", "year": 2014, "n": 18, "topic": "Finance", "subs": ["Processes of financial management"], "img": "2014_Q18.png", "w": 963, "h": 782, "ans": ["D"], "expl": "Reading the Gantt chart: the stock purchase bar begins before the shop refit bar ends, so some stock is purchased before refitting is complete. The other statements contradict the chart's timing."}, {"id": "2014-Q19", "year": 2014, "n": 19, "topic": "Finance", "subs": ["Role of financial management"], "img": "2014_Q19.png", "w": 1029, "h": 1080, "ans": ["A"], "expl": "Current ratio 2014 = 1500 \u00f7 1000 = 1.5:1, up from 1.25:1 in 2013 and above the industry average of 1:1 \u2014 so liquidity is better than industry average AND improved."}, {"id": "2014-Q20", "year": 2014, "n": 20, "topic": "Finance", "subs": ["Processes of financial management"], "img": "2014_Q20.png", "w": 1028, "h": 1040, "ans": ["D"], "expl": "Equity = 10,000 \u2212 7,000 = 3,000, so debt/equity = 7000 \u00f7 3000 \u2248 233%, worse than 150% in 2013 and worse than the 100% industry average \u2014 gearing has worsened on both counts."}, {"id": "2015-Q1", "year": 2015, "n": 1, "topic": "Marketing", "subs": [], "img": "2015_Q1.png", "w": 738, "h": 299, "ans": ["D"], "expl": "Wheat farmers sell raw/primary produce, which is traded in the resource market. Industrial markets buy goods for further processing; intermediate markets buy to resell."}, {"id": "2015-Q2", "year": 2015, "n": 2, "topic": "Human Resources", "subs": ["Human resource strategies", "Processes of human resource management"], "img": "2015_Q2.png", "w": 1029, "h": 329, "ans": ["C"], "expl": "Acquisition covers identifying staffing needs, job analysis, writing job descriptions, recruitment and selection. Training and induction belong to the development/maintenance stages."}, {"id": "2015-Q3", "year": 2015, "n": 3, "topic": "Marketing", "subs": ["Marketing process"], "img": "2015_Q3.png", "w": 939, "h": 360, "ans": ["A"], "expl": "The store collects the data itself (first-hand), so it's primary research, and postcodes reveal where customers come from \u2014 helping define the target market geographically."}, {"id": "2015-Q4", "year": 2015, "n": 4, "topic": "Marketing", "subs": ["Marketing process"], "img": "2015_Q4.png", "w": 1028, "h": 289, "ans": ["B"], "expl": "The situational analysis (including SWOT) is the stage where a business examines its internal strengths/weaknesses and external opportunities/threats \u2014 its internal and external influences."}, {"id": "2015-Q5", "year": 2015, "n": 5, "topic": "Operations", "subs": ["Operations processes"], "img": "2015_Q5.png", "w": 883, "h": 298, "ans": ["C"], "expl": "Transforming resources do the work: facilities and human resources. Customers and materials are transformed resources \u2014 they are changed by the process."}, {"id": "2015-Q6", "year": 2015, "n": 6, "topic": "Finance", "subs": ["Influences on financial management"], "img": "2015_Q6.png", "w": 956, "h": 299, "ans": ["A"], "expl": "New capital is raised in the primary market of the ASX, where new shares are issued to investors. The secondary market only transfers existing shares between investors \u2014 no new funds reach the company."}, {"id": "2015-Q7", "year": 2015, "n": 7, "topic": "Marketing", "subs": ["Marketing strategies"], "img": "2015_Q7.png", "w": 1029, "h": 391, "ans": ["A"], "expl": "Considering time and difficulty means calculating the cost of the job then adding a margin \u2014 cost-based (cost-plus) pricing. Market/competition-based pricing looks outward at demand or rivals instead."}, {"id": "2015-Q8", "year": 2015, "n": 8, "topic": "Operations", "subs": ["Operations strategies"], "img": "2015_Q8.png", "w": 1029, "h": 289, "ans": ["D"], "expl": "Fresh milk is perishable, so the oldest stock must sell first \u2014 first-in-first-out (FIFO). LIFO would leave old milk spoiling at the back."}, {"id": "2015-Q9", "year": 2015, "n": 9, "topic": "Operations", "subs": ["Operations processes", "Operations strategies"], "img": "2015_Q9.png", "w": 767, "h": 360, "ans": ["A"], "expl": "Minimising waste reduces production costs \u2014 the cost performance objective. Speed is about time, flexibility about adapting to change."}, {"id": "2015-Q10", "year": 2015, "n": 10, "topic": "Finance", "subs": ["Influences on financial management"], "img": "2015_Q10.png", "w": 634, "h": 298, "ans": ["D"], "expl": "External equity (issuing shares to new investors) dilutes existing ownership. It has no maturity date and no compulsory interest \u2014 those features belong to debt."}, {"id": "2015-Q11", "year": 2015, "n": 11, "topic": "Human Resources", "subs": ["Human resource strategies", "Key influences"], "img": "2015_Q11.png", "w": 903, "h": 298, "ans": ["D"], "expl": "Performance pay links payment to achieving results \u2014 Sally's department bonus for meeting its sales target. Penalty rates, gifts and above-award wages aren't tied to measured performance."}, {"id": "2015-Q12", "year": 2015, "n": 12, "topic": "Human Resources", "subs": ["Human resource strategies"], "img": "2015_Q12.png", "w": 809, "h": 298, "ans": ["B"], "expl": "Publicity is free media coverage not paid for by the business \u2014 a food critic's independent review. Loyalty schemes and free desserts are sales promotions the business pays for."}, {"id": "2015-Q13", "year": 2015, "n": 13, "topic": "Operations", "subs": ["Operations processes", "Operations strategies"], "img": "2015_Q13.png", "w": 839, "h": 258, "ans": ["B"], "expl": "Compliance costs are the expenses of meeting legal requirements (e.g. licences, reporting, safety standards) \u2014 not competitor prices or customer demands."}, {"id": "2015-Q14", "year": 2015, "n": 14, "topic": "Operations", "subs": ["Operations processes", "Operations strategies"], "img": "2015_Q14.png", "w": 963, "h": 841, "ans": ["C"], "expl": "The critical path is the longest duration path through the network. Here the longest chain of dependent activities totals 18 days."}, {"id": "2015-Q15", "year": 2015, "n": 15, "topic": "Finance", "subs": [], "img": "2015_Q15.png", "w": 981, "h": 800, "ans": ["A"], "expl": "Activity EC is NOT on the critical path and has slack. Even at 6 days its path stays shorter than the 18-day critical path, so the project is delayed by 0 days."}, {"id": "2015-Q16", "year": 2015, "n": 16, "topic": "Finance", "subs": ["Processes of financial management"], "img": "2015_Q16.png", "w": 965, "h": 749, "ans": ["B"], "expl": "Net profit 2014 = gross profit 50 \u2212 expenses 20 = 30. Net profit ratio = 30 \u00f7 150 sales = 20%."}, {"id": "2015-Q17", "year": 2015, "n": 17, "topic": "Finance", "subs": ["Processes of financial management"], "img": "2015_Q17.png", "w": 1029, "h": 904, "ans": ["A"], "expl": "Gross profit ratio rose from 50/150 (33%) to 100/200 (50%) \u2014 improved. Expense ratio fell from 20/150 (13.3%) to 20/200 (10%) \u2014 also improved. Both improved."}, {"id": "2015-Q18", "year": 2015, "n": 18, "topic": "Operations", "subs": ["Influences", "Role of operations management"], "img": "2015_Q18.png", "w": 997, "h": 258, "ans": ["C"], "expl": "Cost leadership means becoming the lowest-cost producer \u2014 the strategy focused on reducing expenses. Differentiation and quality strategies usually add cost."}, {"id": "2015-Q19", "year": 2015, "n": 19, "topic": "Marketing", "subs": ["Marketing process", "Marketing strategies"], "img": "2015_Q19.png", "w": 884, "h": 298, "ans": ["D"], "expl": "Standardised global marketing treats the world as one market with one product/campaign, allowing economies of scale in production and promotion. Catering for local tastes is customisation \u2014 the opposite."}, {"id": "2015-Q20", "year": 2015, "n": 20, "topic": "Marketing", "subs": [], "img": "2015_Q20.png", "w": 1028, "h": 715, "ans": ["B"], "expl": "Market share = program viewers \u00f7 total viewers. Program B: 200,000/1,200,000 = 16.7% rising to 200,000/1,000,000 = 20%. The others stayed flat or fell (A stayed 20%, C fell to 23.3% from 25%, D fell)."}, {"id": "2016-Q1", "year": 2016, "n": 1, "topic": "Marketing", "subs": ["Influences on marketing"], "img": "2016_Q1.png", "w": 1028, "h": 406, "ans": ["D"], "expl": "The Competition and Consumer Act 2010 (Cth) contains the Australian Consumer Law, including consumer guarantees/warranties for faulty goods. It replaced the Trade Practices Act 1974."}, {"id": "2016-Q2", "year": 2016, "n": 2, "topic": "Human Resources", "subs": ["Human resource strategies"], "img": "2016_Q2.png", "w": 1028, "h": 391, "ans": ["D"], "expl": "Ruth was sacked for a harsh, unjust reason (reporting theft) \u2014 unfair dismissal. Redundancy/retrenchment apply when the JOB disappears, which isn't the case."}, {"id": "2016-Q3", "year": 2016, "n": 3, "topic": "Marketing", "subs": ["Marketing process"], "img": "2016_Q3.png", "w": 1028, "h": 347, "ans": ["C"], "expl": "The situational analysis (SWOT) is where a business assesses its current position, including weaknesses like a confusing website. Target markets and objectives come later in the process."}, {"id": "2016-Q4", "year": 2016, "n": 4, "topic": "Finance", "subs": ["Role of financial management"], "img": "2016_Q4.png", "w": 613, "h": 298, "ans": ["C"], "expl": "Solvency is the ability to meet LONG-term financial commitments (measured by gearing). Meeting short-term commitments is liquidity."}, {"id": "2016-Q5", "year": 2016, "n": 5, "topic": "Human Resources", "subs": ["Key influences"], "img": "2016_Q5.png", "w": 1004, "h": 360, "ans": ["C"], "expl": "The Sex Discrimination Act 1984 (Cth) prohibits discrimination on the basis of sex, pregnancy and marital status. The affirmative action act promotes EEO but the direct prohibition is the SDA."}, {"id": "2016-Q6", "year": 2016, "n": 6, "topic": "Operations", "subs": ["Influences", "Operations strategies"], "img": "2016_Q6.png", "w": 1028, "h": 391, "ans": ["D"], "expl": "Lowering average cost per unit by increasing output is the definition of economies of scale. Global sourcing lowers input costs but isn't defined by output volume."}, {"id": "2016-Q7", "year": 2016, "n": 7, "topic": "Marketing", "subs": ["Influences on marketing"], "img": "2016_Q7.png", "w": 1028, "h": 316, "ans": ["D"], "expl": "Buying from a discount store BECAUSE of low income is an economic circumstance, but as a personal financial constraint on the consumer, NESA classified it sociocultural (socioeconomic status is a sociocultural factor \u2014 social class/income group shapes buying habits)."}, {"id": "2016-Q8", "year": 2016, "n": 8, "topic": "Marketing", "subs": [], "img": "2016_Q8.png", "w": 1028, "h": 329, "ans": ["B"], "expl": "Stocking up for new store openings links operations (producing/holding stock) with marketing (the launch and anticipated sales) \u2014 interdependence between operations and marketing."}, {"id": "2016-Q9", "year": 2016, "n": 9, "topic": "Operations", "subs": ["Operations strategies"], "img": "2016_Q9.png", "w": 1028, "h": 329, "ans": ["C"], "expl": "Quality (specifically quality of conformance) measures how well the product meets its prescribed design specifications. Speed measures time; flexibility measures adaptability."}, {"id": "2016-Q10", "year": 2016, "n": 10, "topic": "Finance", "subs": ["Influences on financial management", "Processes of financial management"], "img": "2016_Q10.png", "w": 885, "h": 548, "ans": ["A"], "expl": "Jan close: 4000+20000\u221214000 = 10,000. Feb close: 10,000+20,000\u221250,000 = \u221220,000. Mar close: \u221220,000+20,000\u221224,000 = \u221224,000, which is April's opening balance."}, {"id": "2016-Q11", "year": 2016, "n": 11, "topic": "Finance", "subs": [], "img": "2016_Q11.png", "w": 918, "h": 944, "ans": ["B"], "expl": "Equity = capital 22,700 + net profit 12,800 = $35,500. (Total assets and liabilities aren't needed once capital and retained profit are given.)"}, {"id": "2016-Q12", "year": 2016, "n": 12, "topic": "Finance", "subs": ["Processes of financial management"], "img": "2016_Q12.png", "w": 918, "h": 954, "ans": ["B"], "expl": "Total liabilities + equity = 110,500 + 35,500 = 146,000 = total assets. Non-current assets are 125,000, so current assets = 21,000 (stock = 3,000). Current ratio = 21,000 \u00f7 10,500 = 2:1, close to the 1.9:1 industry standard \u2014 acceptable."}, {"id": "2016-Q13", "year": 2016, "n": 13, "topic": "Marketing", "subs": ["Marketing strategies"], "img": "2016_Q13.png", "w": 1028, "h": 347, "ans": ["D"], "expl": "Samples to loyalty program members = relationship marketing (rewarding existing customers); samples to beauty bloggers = opinion leaders (influencers who shape others' purchases)."}, {"id": "2016-Q14", "year": 2016, "n": 14, "topic": "Marketing", "subs": [], "img": "2016_Q14.png", "w": 1028, "h": 329, "ans": ["C"], "expl": "A unit trust pools many investors' money and invests it in assets such as property; investors hold units in the trust. Buying shares or making bank deposits are not trusts."}, {"id": "2016-Q15", "year": 2016, "n": 15, "topic": "Marketing", "subs": ["Role of marketing"], "img": "2016_Q15.png", "w": 1028, "h": 391, "ans": ["C"], "expl": "Selling direct to the public = consumer market. Selling to supermarkets, who resell = intermediate market. So the change is consumer \u2192 intermediate."}, {"id": "2016-Q16", "year": 2016, "n": 16, "topic": "Human Resources", "subs": ["Key influences"], "img": "2016_Q16.png", "w": 1028, "h": 391, "ans": ["A"], "expl": "Casual employees have no entitlement to notice or redundancy pay, so dismissing the casual first minimises legal risk. Dismissing on the basis of pregnancy or age would be unlawful discrimination."}, {"id": "2016-Q17", "year": 2016, "n": 17, "topic": "Marketing", "subs": ["Marketing strategies"], "img": "2016_Q17.png", "w": 1028, "h": 347, "ans": ["C"], "expl": "Gyms are a business (industrial/B2B) market with few, identifiable buyers \u2014 best reached by personal selling: sales reps demonstrating the product directly. Mass advertising wastes money on non-buyers."}, {"id": "2016-Q18", "year": 2016, "n": 18, "topic": "Marketing", "subs": ["Marketing strategies"], "img": "2016_Q18.png", "w": 1028, "h": 391, "ans": ["D"], "expl": "Employers must hold workers compensation insurance; the insurer ultimately pays the medical costs of a workplace injury. WorkCover regulates the scheme but doesn't pay claims for the employer."}, {"id": "2016-Q19", "year": 2016, "n": 19, "topic": "Finance", "subs": ["Processes of financial management"], "img": "2016_Q19.png", "w": 889, "h": 719, "ans": ["A"], "expl": "Net profit ratio: A = 400k/1.6m = 25% vs B = 400k/2.8m = 14.3% \u2014 A more profitable. Receivables turnover: A = 8 times vs B = 11.2 times \u2014 A less efficient. So A is more profitable but less efficient."}, {"id": "2016-Q20", "year": 2016, "n": 20, "topic": "Human Resources", "subs": ["Key influences"], "img": "2016_Q20.png", "w": 1028, "h": 347, "ans": ["B"], "expl": "An independent contractor works under a contract FOR service (a commercial contract), not a contract OF service (employment). Awards, enterprise agreements and the NES only cover employees."}, {"id": "2017-Q1", "year": 2017, "n": 1, "topic": "Human Resources", "subs": ["Human resource strategies"], "img": "2017_Q1.png", "w": 853, "h": 360, "ans": ["B"], "expl": "Recruitment (attracting applicants) is a core process of the human resources function. Marketing, finance and operations don't handle staffing."}, {"id": "2017-Q2", "year": 2017, "n": 2, "topic": "Operations", "subs": ["Operations strategies"], "img": "2017_Q2.png", "w": 809, "h": 299, "ans": ["D"], "expl": "Continuous improvement (kaizen) is a core principle of Total Quality Management \u2014 an ongoing, organisation-wide commitment to improving quality. Quality assurance is about meeting set standards, not continuous improvement."}, {"id": "2017-Q3", "year": 2017, "n": 3, "topic": "Marketing", "subs": ["Marketing process"], "img": "2017_Q3.png", "w": 1028, "h": 347, "ans": ["A"], "expl": "The gym uses an internal capability \u2014 extending its own opening hours (a strength) \u2014 to counter the external threat of a new competitor. So: a strength to overcome a threat."}, {"id": "2017-Q4", "year": 2017, "n": 4, "topic": "Finance", "subs": ["Role of financial management"], "img": "2017_Q4.png", "w": 693, "h": 360, "ans": ["C", "D"], "expl": "Paying debts 'as they fall due' describes meeting financial commitments. NESA accepted both liquidity (short-term debts) and solvency (all debts) for this question, as the wording doesn't specify the time frame."}, {"id": "2017-Q5", "year": 2017, "n": 5, "topic": "Marketing", "subs": ["Marketing strategies"], "img": "2017_Q5.png", "w": 816, "h": 360, "ans": ["C"], "expl": "Selling only to major supermarkets \u2014 a limited number of chosen outlets \u2014 is selective distribution. Exclusive uses a single outlet; intensive uses as many as possible."}, {"id": "2017-Q6", "year": 2017, "n": 6, "topic": "Finance", "subs": ["Influences on financial management"], "img": "2017_Q6.png", "w": 609, "h": 360, "ans": ["D"], "expl": "The owner's own money invested in the business is equity, and because it comes from the owner (inside the business entity's ownership) it is internal equity finance. Debt would involve borrowing from outsiders."}, {"id": "2017-Q7", "year": 2017, "n": 7, "topic": "Marketing", "subs": ["Influences on marketing"], "img": "2017_Q7.png", "w": 1028, "h": 347, "ans": ["C"], "expl": "Friends' opinions shaping Vinh's purchase is a sociocultural influence (peer group/social factors). Psychological would be his own internal perceptions and motives."}, {"id": "2017-Q8", "year": 2017, "n": 8, "topic": "Marketing", "subs": ["Influences on marketing", "Marketing strategies"], "img": "2017_Q8.png", "w": 977, "h": 360, "ans": ["A"], "expl": "Consumer law implies conditions into every sale \u2014 goods must be fit for purpose. A chainsaw that can't cut branches breaches implied conditions, requiring a refund."}, {"id": "2017-Q9", "year": 2017, "n": 9, "topic": "Operations", "subs": ["Operations processes"], "img": "2017_Q9.png", "w": 576, "h": 298, "ans": ["D"], "expl": "Gantt charts schedule tasks over time during the transformation process \u2014 they're a tool for monitoring/planning production tasks within transformation."}, {"id": "2017-Q10", "year": 2017, "n": 10, "topic": "Marketing", "subs": ["Influences on marketing", "Marketing strategies"], "img": "2017_Q10.png", "w": 1010, "h": 747, "ans": ["D"], "expl": "Same product, same ingredients, different prices for different customer groups (teenagers vs adults) is price discrimination \u2014 charging different markets different prices for the same product."}, {"id": "2017-Q11", "year": 2017, "n": 11, "topic": "Human Resources", "subs": [], "img": "2017_Q11.png", "w": 1028, "h": 329, "ans": ["B"], "expl": "Business flexibility, expansion and competitiveness are employer interests \u2014 represented by employer associations when lobbying government. Unions represent employees."}, {"id": "2017-Q12", "year": 2017, "n": 12, "topic": "Finance", "subs": ["Processes of financial management"], "img": "2017_Q12.png", "w": 939, "h": 298, "ans": ["D"], "expl": "Efficiency ratios measure how well assets are managed \u2014 the accounts receivable turnover ratio shows how quickly debts are collected. Gross profit ratio measures profitability."}, {"id": "2017-Q13", "year": 2017, "n": 13, "topic": "Finance", "subs": [], "img": "2017_Q13.png", "w": 672, "h": 298, "ans": ["A"], "expl": "Factoring is selling accounts receivable at a discount for immediate cash \u2014 its purpose is to improve cash flow now, at the cost of receiving less than face value."}, {"id": "2017-Q14", "year": 2017, "n": 14, "topic": "Marketing", "subs": [], "img": "2017_Q14.png", "w": 1028, "h": 286, "ans": ["B"], "expl": "The pasta manufacturer buys flour as an input for further production \u2014 that's the industrial market (goods bought for use in producing other goods)."}, {"id": "2017-Q15", "year": 2017, "n": 15, "topic": "Finance", "subs": ["Processes of financial management"], "img": "2017_Q15.png", "w": 1028, "h": 579, "ans": ["D"], "expl": "Raw totals mislead because the businesses differ in size. Comparative ratio analysis standardises performance (e.g. return on assets), allowing a fair like-for-like comparison."}, {"id": "2017-Q16", "year": 2017, "n": 16, "topic": "Operations", "subs": ["Influences", "Role of operations management"], "img": "2017_Q16.png", "w": 946, "h": 299, "ans": ["C"], "expl": "CSR goes beyond legal obligations for the benefit of society \u2014 a community health program. Compensation payments are legally required; sponsorship is promotion."}, {"id": "2017-Q17", "year": 2017, "n": 17, "topic": "Finance", "subs": ["Processes of financial management"], "img": "2017_Q17.png", "w": 874, "h": 255, "ans": ["A"], "expl": "Sales = COGS + expenses + net profit, so GP ratio \u2212 NP ratio = expense ratio: (GP \u2212 NP) \u00f7 sales = expenses \u00f7 sales. It is always that difference. It is smaller than the gross profit ratio, not greater."}, {"id": "2017-Q18", "year": 2017, "n": 18, "topic": "Finance", "subs": ["Influences on financial management"], "img": "2017_Q18.png", "w": 1028, "h": 329, "ans": ["A"], "expl": "ASIC (Australian Securities and Investments Commission) enforces company and financial services laws to ensure companies operate financially responsibly. APRA supervises banks/insurers; the RBA sets monetary policy."}, {"id": "2017-Q19", "year": 2017, "n": 19, "topic": "Human Resources", "subs": ["Processes of human resource management"], "img": "2017_Q19.png", "w": 1028, "h": 391, "ans": ["C"], "expl": "Limiting after-hours work email addresses work\u2013life balance \u2014 a social influence on human resource management. It's not legally required (legal) or about costs (economic)."}, {"id": "2017-Q20", "year": 2017, "n": 20, "topic": "Finance", "subs": ["Processes of financial management"], "img": "2017_Q20.png", "w": 961, "h": 836, "ans": ["D"], "expl": "Sales = 400,000 \u00f7 0.667 = $600,000. Net profit = 50% \u00d7 600,000 = $300,000. So sales $600,000 and net profit $300,000."}, {"id": "2018-Q1", "year": 2018, "n": 1, "topic": "Human Resources", "subs": ["Key influences"], "img": "2018_Q1.png", "w": 1028, "h": 391, "ans": ["C"], "expl": "40 hours per week with sick leave, paid annual leave and superannuation = permanent full-time. Casuals get a loading instead of paid leave; part-time is fewer than 38 hours."}, {"id": "2018-Q2", "year": 2018, "n": 2, "topic": "Marketing", "subs": ["Marketing strategies"], "img": "2018_Q2.png", "w": 987, "h": 360, "ans": ["A"], "expl": "Selling via social media is e-marketing \u2014 using electronic/online platforms to market products. Personal selling involves face-to-face contact."}, {"id": "2018-Q3", "year": 2018, "n": 3, "topic": "Operations", "subs": ["Operations strategies"], "img": "2018_Q3.png", "w": 1028, "h": 347, "ans": ["C"], "expl": "Scanning and learning means observing global best practice (e.g. at trade fairs) and adopting better methods. It's how operations managers keep up with efficient techniques worldwide."}, {"id": "2018-Q4", "year": 2018, "n": 4, "topic": "Human Resources", "subs": ["Processes of human resource management"], "img": "2018_Q4.png", "w": 945, "h": 298, "ans": ["D"], "expl": "Voluntary separation is initiated by the employee \u2014 resignation. Dismissal is involuntary (employer-initiated); promotion isn't separation at all."}, {"id": "2018-Q5", "year": 2018, "n": 5, "topic": "Marketing", "subs": ["Marketing strategies", "Role of marketing"], "img": "2018_Q5.png", "w": 1028, "h": 391, "ans": ["C"], "expl": "A distinctive image used consistently on the website and vehicles is product branding \u2014 creating a recognisable identity. Positioning is about image relative to competitors; this is simply brand recognition."}, {"id": "2018-Q6", "year": 2018, "n": 6, "topic": "Operations", "subs": ["Influences", "Operations strategies"], "img": "2018_Q6.png", "w": 1028, "h": 391, "ans": ["D"], "expl": "Lower price per kilogram from buying larger quantities is a purchasing economy of scale \u2014 unit input costs fall as volume rises."}, {"id": "2018-Q7", "year": 2018, "n": 7, "topic": "Finance", "subs": ["Influences on financial management"], "img": "2018_Q7.png", "w": 1028, "h": 285, "ans": ["D"], "expl": "Extra stock before a busy period is a short-term need: retained profits (internal, no cost) and a bank overdraft (short-term debt) both suit. Debentures and unsecured notes are longer-term instruments."}, {"id": "2018-Q8", "year": 2018, "n": 8, "topic": "Human Resources", "subs": ["Key influences"], "img": "2018_Q8.png", "w": 1028, "h": 360, "ans": ["B"], "expl": "The Fair Work Commission FINALISED (decided) the dispute \u2014 that's arbitration: a third party hears both sides and makes a binding determination. Mediation only facilitates discussion without imposing a decision."}, {"id": "2018-Q9", "year": 2018, "n": 9, "topic": "Operations", "subs": ["Operations strategies"], "img": "2018_Q9.png", "w": 1028, "h": 391, "ans": ["D"], "expl": "Flexibility is the ability to adjust operations to changes in demand \u2014 exactly what's needed for seasonal soup demand. Dependability is consistency; customisation is individualised products."}, {"id": "2018-Q10", "year": 2018, "n": 10, "topic": "Marketing", "subs": ["Marketing strategies"], "img": "2018_Q10.png", "w": 1028, "h": 329, "ans": ["A"], "expl": "Focus groups gather customer feedback to evaluate and shape products \u2014 a marketing approach, which starts with understanding customer needs. A selling approach would just push the existing product."}, {"id": "2018-Q11", "year": 2018, "n": 11, "topic": "Human Resources", "subs": ["Key influences"], "img": "2018_Q11.png", "w": 1028, "h": 347, "ans": ["B"], "expl": "Job sharing is a flexible working condition, and the driver \u2014 employees seeking work\u2013life balance \u2014 is a social influence on HR management."}, {"id": "2018-Q12", "year": 2018, "n": 12, "topic": "Finance", "subs": ["Processes of financial management"], "img": "2018_Q12.png", "w": 1028, "h": 391, "ans": ["C"], "expl": "Comparative ratio analysis compares a business's ratios with SIMILAR businesses (and over time), so Kevin can evaluate which investment performs better on a like-for-like basis."}, {"id": "2018-Q13", "year": 2018, "n": 13, "topic": "Operations", "subs": ["Influences", "Operations strategies", "Role of operations management"], "img": "2018_Q13.png", "w": 1028, "h": 391, "ans": ["A"], "expl": "Organising transport of raw materials and finished products is logistics \u2014 the physical distribution side of operations, covering transport, storage and distribution."}, {"id": "2018-Q14", "year": 2018, "n": 14, "topic": "Marketing", "subs": ["Marketing strategies"], "img": "2018_Q14.png", "w": 1028, "h": 391, "ans": ["C"], "expl": "Product safety recalls are driven by government legislation/consumer law \u2014 products posing health risks must be removed. It's a legal influence, not an economic or competitive one."}, {"id": "2018-Q15", "year": 2018, "n": 15, "topic": "Operations", "subs": ["Operations strategies", "Role of operations management"], "img": "2018_Q15.png", "w": 1028, "h": 285, "ans": ["B"], "expl": "Outsourcing manufacturing overseas means the foreign workers are NOT the company's employees, so Australian HR compliance costs (awards, super, workers comp) don't apply. It gives up direct control of production costs and staff."}, {"id": "2018-Q16", "year": 2018, "n": 16, "topic": "Operations", "subs": ["Influences", "Operations processes"], "img": "2018_Q16.png", "w": 842, "h": 298, "ans": ["A"], "expl": "Transformed resources \u2014 the things changed by the process \u2014 are materials, information and customers. Facilities, human resources and technology are transforming resources."}, {"id": "2018-Q17", "year": 2018, "n": 17, "topic": "Marketing", "subs": ["Marketing strategies"], "img": "2018_Q17.png", "w": 1028, "h": 391, "ans": ["D"], "expl": "Uniforms, staff presentation and cleanliness are physical evidence \u2014 the tangible cues customers use to judge a service. They're part of the extended (7 P's) marketing mix for services."}, {"id": "2018-Q18", "year": 2018, "n": 18, "topic": "Finance", "subs": ["Influences on financial management", "Processes of financial management"], "img": "2018_Q18.png", "w": 1028, "h": 347, "ans": ["D"], "expl": "A higher AUD means Canadian buyers need more Canadian dollars to buy Australian goods \u2014 Australian products become more expensive for Canadian businesses, hurting Australian exporters."}, {"id": "2018-Q19", "year": 2018, "n": 19, "topic": "Finance", "subs": ["Processes of financial management"], "img": "2018_Q19.png", "w": 934, "h": 929, "ans": ["B"], "expl": "Gross profit = 600,000 \u2212 200,000 = 400,000. Gross profit ratio = 400,000 \u00f7 600,000 = 67%."}, {"id": "2018-Q20", "year": 2018, "n": 20, "topic": "Finance", "subs": [], "img": "2018_Q20.png", "w": 934, "h": 885, "ans": ["B"], "expl": "Receivables turnover = 600,000 \u00f7 41,000 \u2248 14.6 times per year. 365 \u00f7 14.6 \u2248 25 days on average to collect debts."}, {"id": "2019-Q1", "year": 2019, "n": 1, "topic": "Marketing", "subs": [], "img": "2019_Q1.png", "w": 925, "h": 360, "ans": ["C"], "expl": "Custom-made, high-fashion clothes serve a small, specialised segment \u2014 a niche market. Mass markets serve broad populations with standardised products."}, {"id": "2019-Q2", "year": 2019, "n": 2, "topic": "Finance", "subs": ["Influences on financial management"], "img": "2019_Q2.png", "w": 696, "h": 360, "ans": ["B"], "expl": "A mortgage is long-term debt secured against property \u2014 the standard source of finance for purchasing premises. Debentures/shares raise funds but aren't property-specific."}, {"id": "2019-Q3", "year": 2019, "n": 3, "topic": "Human Resources", "subs": ["Human resource strategies"], "img": "2019_Q3.png", "w": 1014, "h": 316, "ans": ["A"], "expl": "In a crisis requiring immediate decisions, autocratic leadership works: the manager decides quickly without consultation. Democratic styles are slower; laissez-faire gives no direction."}, {"id": "2019-Q4", "year": 2019, "n": 4, "topic": "Finance", "subs": ["Influences on financial management"], "img": "2019_Q4.png", "w": 799, "h": 360, "ans": ["C"], "expl": "Finance companies specialise in leasing equipment and providing loans to businesses. Unit trusts and superannuation funds are investment vehicles, not equipment lessors."}, {"id": "2019-Q5", "year": 2019, "n": 5, "topic": "Marketing", "subs": ["Marketing strategies"], "img": "2019_Q5.png", "w": 800, "h": 360, "ans": ["D"], "expl": "Organic bread in health food stores targets a specific segment through a limited number of relevant outlets \u2014 selective distribution. Intensive would put it everywhere."}, {"id": "2019-Q6", "year": 2019, "n": 6, "topic": "Marketing", "subs": ["Marketing strategies"], "img": "2019_Q6.png", "w": 1028, "h": 391, "ans": ["B"], "expl": "Pricing below cost to attract customers (expecting them to buy other items) is the loss leader strategy. Penetration is low pricing for a NEW product to gain share, not below-cost pricing of an existing one."}, {"id": "2019-Q7", "year": 2019, "n": 7, "topic": "Marketing", "subs": ["Influences on marketing", "Marketing process"], "img": "2019_Q7.png", "w": 825, "h": 254, "ans": ["A"], "expl": "Sugging = 'selling under the guise' of market research \u2014 a sales pitch disguised as a survey. Telemarketing is open selling by phone."}, {"id": "2019-Q8", "year": 2019, "n": 8, "topic": "Finance", "subs": ["Financial management strategies", "Influences on financial management"], "img": "2019_Q8.png", "w": 1028, "h": 416, "ans": ["D"], "expl": "A global downturn cuts demand for exports: Australian output falls, unemployment rises, and the exchange rate falls (less demand for AUD). Increase / Decrease / Decrease."}, {"id": "2019-Q9", "year": 2019, "n": 9, "topic": "Operations", "subs": ["Operations strategies"], "img": "2019_Q9.png", "w": 973, "h": 360, "ans": ["A"], "expl": "Inspections that detect defects are quality control \u2014 checking output against standards. Quality assurance prevents defects through systems; improvement is ongoing enhancement."}, {"id": "2019-Q10", "year": 2019, "n": 10, "topic": "Human Resources", "subs": ["Human resource strategies"], "img": "2019_Q10.png", "w": 791, "h": 298, "ans": ["B"], "expl": "Disputes escalate from least to most formal: negotiation (parties talk), then mediation (third party assists), then courts and tribunals (binding rulings)."}, {"id": "2019-Q11", "year": 2019, "n": 11, "topic": "Operations", "subs": ["Operations strategies", "Role of operations management"], "img": "2019_Q11.png", "w": 1028, "h": 347, "ans": ["A"], "expl": "Buying generic (cheapest) inputs to keep prices low is cost leadership \u2014 competing by being the lowest-cost operator. Economies of scale relate to volume, which a sole trader lacks."}, {"id": "2019-Q12", "year": 2019, "n": 12, "topic": "Marketing", "subs": ["Marketing strategies"], "img": "2019_Q12.png", "w": 1028, "h": 329, "ans": ["B"], "expl": "Placements issue additional shares at a discount to selected existing shareholders/institutions. New issues are open to the public; private equity is for unlisted companies."}, {"id": "2019-Q13", "year": 2019, "n": 13, "topic": "Operations", "subs": ["Operations processes", "Operations strategies", "Role of operations management"], "img": "2019_Q13.png", "w": 935, "h": 792, "ans": ["C", "D"], "expl": "Reading the Gantt chart, the 'manufacture item' bar begins in the March\u2013April period; NESA accepted both March and April as correct due to the chart's ambiguity."}, {"id": "2019-Q14", "year": 2019, "n": 14, "topic": "Finance", "subs": ["Processes of financial management"], "img": "2019_Q14.png", "w": 1028, "h": 382, "ans": ["C"], "expl": "Financial planning order: determine financial needs \u2192 develop budgets \u2192 maintain record systems \u2192 identify financial risks \u2192 establish financial controls. Needs must come first; controls last."}, {"id": "2019-Q15", "year": 2019, "n": 15, "topic": "Finance", "subs": ["Influences on financial management", "Processes of financial management"], "img": "2019_Q15.png", "w": 954, "h": 984, "ans": ["C"], "expl": "Total liabilities = 10,000 + 5,000 + 135,000 = 150,000. Total equity = 184,000 + 16,000 = 200,000. Gearing = 150,000 \u00f7 200,000 = 0.75:1."}, {"id": "2019-Q16", "year": 2019, "n": 16, "topic": "Finance", "subs": ["Influences on financial management"], "img": "2019_Q16.png", "w": 1028, "h": 285, "ans": ["D"], "expl": "ASIC is the independent federal regulator ensuring companies comply with regulations, keep proper financial records and protect consumers of financial services. APRA supervises deposit-takers and insurers."}, {"id": "2019-Q17", "year": 2019, "n": 17, "topic": "Operations", "subs": ["Operations processes", "Operations strategies"], "img": "2019_Q17.png", "w": 1026, "h": 844, "ans": ["D"], "expl": "Business D combines high output per employee (14) with high accidents (4) \u2014 output has risen at the cost of safety. B has the same output with the fewest accidents."}, {"id": "2019-Q18", "year": 2019, "n": 18, "topic": "Operations", "subs": ["Operations processes", "Operations strategies"], "img": "2019_Q18.png", "w": 963, "h": 799, "ans": ["B"], "expl": "Business B has the best combination: lowest absenteeism (5), fewest accidents (2), lowest turnover (9%) and highest output (14) \u2014 effective HR management across all indicators."}, {"id": "2019-Q19", "year": 2019, "n": 19, "topic": "Operations", "subs": ["Operations strategies"], "img": "2019_Q19.png", "w": 959, "h": 1007, "ans": ["D"], "expl": "Task D depends on all preceding paths converging into it: A, B, C plus the parallel E and F must all finish first \u2014 A, B, C, E, F only."}, {"id": "2019-Q20", "year": 2019, "n": 20, "topic": "Operations", "subs": ["Influences", "Operations processes", "Operations strategies"], "img": "2019_Q20.png", "w": 1028, "h": 1024, "ans": ["C"], "expl": "With C\u2192D reduced to one day, recalculate each path: the longest path through the network now totals 6 days \u2014 the new critical path length."}, {"id": "2020-Q1", "year": 2020, "n": 1, "topic": "Human Resources", "subs": ["Processes of human resource management"], "img": "2020_Q1.png", "w": 985, "h": 431, "ans": ["B"], "expl": "Training raises current job skills; development prepares employees for future roles and increases retention. 'Increase staff skills' + 'retain experienced staff' shows a benefit of each."}, {"id": "2020-Q2", "year": 2020, "n": 2, "topic": "Human Resources", "subs": ["Key influences"], "img": "2020_Q2.png", "w": 1028, "h": 391, "ans": ["D"], "expl": "The right to request flexible working arrangements is one of the minimum employment standards (the NES) in the Fair Work Act 2009. Awards and agreements build on these minimums."}, {"id": "2020-Q3", "year": 2020, "n": 3, "topic": "Human Resources", "subs": ["Human resource strategies", "Processes of human resource management"], "img": "2020_Q3.png", "w": 1028, "h": 347, "ans": ["B"], "expl": "The firm can outsource its recruitment/hiring process to an external specialist (e.g. a recruitment agency) \u2014 outsourcing an HR function it no longer has time to manage internally."}, {"id": "2020-Q4", "year": 2020, "n": 4, "topic": "Marketing", "subs": [], "img": "2020_Q4.png", "w": 979, "h": 298, "ans": ["A"], "expl": "Consumer guarantees require goods to match their description. Refunds aren't required for change of mind, customer damage, or cheaper prices elsewhere."}, {"id": "2020-Q5", "year": 2020, "n": 5, "topic": "Marketing", "subs": ["Marketing process"], "img": "2020_Q5.png", "w": 1028, "h": 391, "ans": ["A"], "expl": "Primary data is collected first-hand by the business \u2014 a customer survey. Journals and ABS data are secondary data (already published by others)."}, {"id": "2020-Q6", "year": 2020, "n": 6, "topic": "Operations", "subs": ["Operations strategies"], "img": "2020_Q6.png", "w": 866, "h": 299, "ans": ["C"], "expl": "Economies of scale = lower per-unit input/production costs as output volume increases. That cost advantage is the main benefit."}, {"id": "2020-Q7", "year": 2020, "n": 7, "topic": "Operations", "subs": ["Operations strategies", "Role of operations management"], "img": "2020_Q7.png", "w": 1028, "h": 285, "ans": ["B"], "expl": "Manufacturing locally lets a business closely oversee production \u2014 maintaining quality control. Overseas manufacturing offers lower wages but less direct quality oversight."}, {"id": "2020-Q8", "year": 2020, "n": 8, "topic": "Marketing", "subs": ["Marketing strategies"], "img": "2020_Q8.png", "w": 944, "h": 821, "ans": ["A"], "expl": "Product B ('Miller's Farm Fruit Oats') carries a brand name; Product A is generic ('Fruit Oats'). The added element is branding \u2014 a name identifying the maker."}, {"id": "2020-Q9", "year": 2020, "n": 9, "topic": "Marketing", "subs": ["Influences on marketing"], "img": "2020_Q9.png", "w": 1028, "h": 329, "ans": ["B"], "expl": "In the downswing businesses first cut hours as demand softens \u2014 before the deeper cuts (redundancies) of a recession. In boom/upswing they'd be adding hours."}, {"id": "2020-Q10", "year": 2020, "n": 10, "topic": "Marketing", "subs": ["Marketing process"], "img": "2020_Q10.png", "w": 1028, "h": 347, "ans": ["D"], "expl": "Cutting the price to clear stock before a replacement model arrives signals the decline stage \u2014 the product is being phased out."}, {"id": "2020-Q11", "year": 2020, "n": 11, "topic": "Operations", "subs": ["Operations strategies"], "img": "2020_Q11.png", "w": 984, "h": 360, "ans": ["A"], "expl": "Just-in-time minimises stock held on site \u2014 inputs arrive only when needed \u2014 directly reducing storage costs and the stock available to steal."}, {"id": "2020-Q12", "year": 2020, "n": 12, "topic": "Human Resources", "subs": ["Key influences"], "img": "2020_Q12.png", "w": 1028, "h": 391, "ans": ["B"], "expl": "Return-to-work plans for injured employees are required by the Workers Compensation Act 1987 (NSW), developed with the insurer. WHS law aims to PREVENT injuries; workers comp manages them after they occur."}, {"id": "2020-Q13", "year": 2020, "n": 13, "topic": "Operations", "subs": ["Influences", "Operations strategies"], "img": "2020_Q13.png", "w": 1028, "h": 391, "ans": ["C"], "expl": "Examining global trends and best practice before designing products is scanning and learning \u2014 monitoring the world's best methods and adopting them."}, {"id": "2020-Q14", "year": 2020, "n": 14, "topic": "Finance", "subs": ["Processes of financial management"], "img": "2020_Q14.png", "w": 1028, "h": 347, "ans": ["C"], "expl": "One-off items like proceeds from selling equipment should be removed (normalised) to show recurring earnings. Including them distorts the picture \u2014 the limitation of normalised earnings."}, {"id": "2020-Q15", "year": 2020, "n": 15, "topic": "Operations", "subs": ["Operations processes", "Operations strategies"], "img": "2020_Q15.png", "w": 1028, "h": 422, "ans": ["D"], "expl": "Made-to-order sandwiches with customer-chosen fillings = customisation; fresh variety baked through the day = quality. Cost/efficiency would push toward standardisation instead."}, {"id": "2020-Q16", "year": 2020, "n": 16, "topic": "Finance", "subs": [], "img": "2020_Q16.png", "w": 1028, "h": 782, "ans": ["B"], "expl": "Lavender Bodywash is the only product that missed its planned results in BOTH halves of the year (8,000 vs 8,500 and 8,500 vs 9,500) \u2014 the clear candidate for deletion."}, {"id": "2020-Q17", "year": 2020, "n": 17, "topic": "Finance", "subs": ["Processes of financial management"], "img": "2020_Q17.png", "w": 1028, "h": 934, "ans": ["C"], "expl": "Gross profit 2020 = 275,000 \u2212 145,000 = $130,000. Net profit = 130,000 \u2212 35,000 = 95,000. Net profit ratio = 95,000 \u00f7 275,000 = 34.5%."}, {"id": "2020-Q18", "year": 2020, "n": 18, "topic": "Finance", "subs": ["Processes of financial management"], "img": "2020_Q18.png", "w": 1028, "h": 886, "ans": ["A"], "expl": "GP ratio: 105/250 (42%) \u2192 130/275 (47.3%) \u2014 improved. Expense ratio: 35/250 (14%) \u2192 35/275 (12.7%) \u2014 improved. Both improved."}, {"id": "2020-Q19", "year": 2020, "n": 19, "topic": "Finance", "subs": ["Role of financial management"], "img": "2020_Q19.png", "w": 919, "h": 981, "ans": ["C"], "expl": "Current ratio 2020 = 1700 \u00f7 1100 \u2248 1.55:1 \u2014 up from 1.25:1 (improved) but still below the 2:1 industry average (worse than industry)."}, {"id": "2020-Q20", "year": 2020, "n": 20, "topic": "Finance", "subs": ["Processes of financial management"], "img": "2020_Q20.png", "w": 919, "h": 938, "ans": ["D"], "expl": "Equity = (1700+8650) \u2212 (1100+6500) = 2750. Debt/equity = 7600 \u00f7 2750 \u2248 276% \u2014 worse than 200% in 2019 and far worse than the 100% industry average."}, {"id": "2021-Q1", "year": 2021, "n": 1, "topic": "Finance", "subs": ["Processes of financial management"], "img": "2021_Q1.png", "w": 813, "h": 298, "ans": ["B"], "expl": "Cost centres are set up to monitor and control EXPENSES for a particular part of the business, making managers accountable for the costs they generate."}, {"id": "2021-Q2", "year": 2021, "n": 2, "topic": "Human Resources", "subs": ["Human resource strategies"], "img": "2021_Q2.png", "w": 947, "h": 298, "ans": ["C"], "expl": "Induction (orienting new staff) and recruitment (attracting applicants) are both HR processes. Pricing is marketing; scheduling is operations; receivables is finance."}, {"id": "2021-Q3", "year": 2021, "n": 3, "topic": "Operations", "subs": ["Influences", "Operations strategies"], "img": "2021_Q3.png", "w": 1028, "h": 359, "ans": ["A"], "expl": "Leading edge technology delivers higher quality/faster output (advantage) but requires high initial investment (disadvantage). It is by definition NOT yet 'proven' or 'widely accepted' \u2014 that's established technology."}, {"id": "2021-Q4", "year": 2021, "n": 4, "topic": "Human Resources", "subs": ["Key influences"], "img": "2021_Q4.png", "w": 985, "h": 298, "ans": ["D"], "expl": "Common law contracts are individual agreements between an employee and employer, covering matters not in awards/agreements. The FWC and BOOT apply to enterprise agreements, not common law contracts."}, {"id": "2021-Q5", "year": 2021, "n": 5, "topic": "Marketing", "subs": ["Influences on marketing"], "img": "2021_Q5.png", "w": 1028, "h": 391, "ans": ["C"], "expl": "Buying expensive clothing because of personal BELIEFS about quality and durability reflects psychological factors \u2014 individual perceptions, motives and attitudes."}, {"id": "2021-Q6", "year": 2021, "n": 6, "topic": "Human Resources", "subs": ["Human resource strategies", "Processes of human resource management"], "img": "2021_Q6.png", "w": 1028, "h": 416, "ans": ["A"], "expl": "A recession cuts tourism demand: separations (retrenchments) increase (process effect) and monetary rewards like bonuses fall (strategy effect). Acquisition and training spending would shrink, not grow."}, {"id": "2021-Q7", "year": 2021, "n": 7, "topic": "Marketing", "subs": ["Marketing strategies"], "img": "2021_Q7.png", "w": 1028, "h": 377, "ans": ["A"], "expl": "Sponsoring the competition is advertising (paid promotion); the TV news report is publicity (free, unpaid media coverage). Together: publicity and advertising."}, {"id": "2021-Q8", "year": 2021, "n": 8, "topic": "Marketing", "subs": [], "img": "2021_Q8.png", "w": 1028, "h": 501, "ans": ["B"], "expl": "The farmer sells raw produce to a manufacturer for processing \u2014 industrial market. The manufacturer sells to supermarkets who resell \u2014 intermediate market."}, {"id": "2021-Q9", "year": 2021, "n": 9, "topic": "Marketing", "subs": ["Marketing process", "Marketing strategies"], "img": "2021_Q9.png", "w": 1028, "h": 391, "ans": ["A"], "expl": "Advertising effectiveness is judged by results: changes in sales and market share directly measure whether the campaign worked. SWOT and product life cycle are planning tools, not evaluation metrics."}, {"id": "2021-Q10", "year": 2021, "n": 10, "topic": "Operations", "subs": ["Operations processes", "Role of operations management"], "img": "2021_Q10.png", "w": 1028, "h": 347, "ans": ["B"], "expl": "Cost leaders standardise: high volume spreads fixed costs (economies of scale) and low variety keeps processes simple and cheap \u2014 high volume, low variety."}, {"id": "2021-Q11", "year": 2021, "n": 11, "topic": "Operations", "subs": ["Influences", "Operations processes", "Operations strategies"], "img": "2021_Q11.png", "w": 1028, "h": 391, "ans": ["B"], "expl": "Global sourcing risks include longer, more complex supply chains (delays) and higher transport costs. It usually INCREASES access to specialist suppliers \u2014 that's a benefit, not a negative."}, {"id": "2021-Q12", "year": 2021, "n": 12, "topic": "Operations", "subs": ["Influences", "Operations processes"], "img": "2021_Q12.png", "w": 1028, "h": 391, "ans": ["C"], "expl": "CSR through the OPERATIONS PROCESS means changing what/how they produce \u2014 offering healthier menu options. Donations are CSR but don't change operations; compensation is a legal requirement."}, {"id": "2021-Q13", "year": 2021, "n": 13, "topic": "Finance", "subs": [], "img": "2021_Q13.png", "w": 941, "h": 504, "ans": ["B"], "expl": "Expenses = gross profit \u2212 net profit. Year 1: 80 \u2212 30 = 50. Year 2: 60 \u2212 30 = 30. Expenses fell from $50m to $30m \u2014 expenses decreased (that's how net profit held at 30 despite lower gross profit)."}, {"id": "2021-Q14", "year": 2021, "n": 14, "topic": "Operations", "subs": ["Operations strategies"], "img": "2021_Q14.png", "w": 1028, "h": 391, "ans": ["C"], "expl": "A longer warranty is only viable if products are reliable enough not to generate mass claims \u2014 i.e. if current quality management strategies could support it. Otherwise warranty costs would explode."}, {"id": "2021-Q15", "year": 2021, "n": 15, "topic": "Human Resources", "subs": ["Human resource strategies", "Key influences"], "img": "2021_Q15.png", "w": 1028, "h": 679, "ans": ["D"], "expl": "Pay per delivery explains everything: drivers work more/faster (deliveries up, absenteeism down) but rush (accidents up 100%) and feel pressured (satisfaction down) \u2014 performance-based pay replacing fixed salary."}, {"id": "2021-Q16", "year": 2021, "n": 16, "topic": "Marketing", "subs": ["Marketing strategies"], "img": "2021_Q16.png", "w": 940, "h": 254, "ans": ["A"], "expl": "A production approach works while demand exceeds supply. When competition increases, a business must actively persuade customers to choose IT \u2014 shifting to a selling approach."}, {"id": "2021-Q17", "year": 2021, "n": 17, "topic": "Finance", "subs": [], "img": "2021_Q17.png", "w": 1028, "h": 391, "ans": ["C"], "expl": "A genuine redundancy defence requires evidence the JOB was no longer needed \u2014 financial records showing losses from poor sales. Evidence of misconduct supports dismissal, not redundancy; a replacement employee would prove it wasn't genuine."}, {"id": "2021-Q18", "year": 2021, "n": 18, "topic": "Finance", "subs": ["Influences on financial management", "Role of financial management"], "img": "2021_Q18.png", "w": 637, "h": 299, "ans": ["B"], "expl": "Factoring converts receivables to immediate cash (better cash flow), but the factor pays less than face value \u2014 the discount reduces profitability."}, {"id": "2021-Q19", "year": 2021, "n": 19, "topic": "Finance", "subs": ["Financial management strategies", "Influences on financial management"], "img": "2021_Q19.png", "w": 1028, "h": 515, "ans": ["D"], "expl": "Payment is in AUD in 60 days, so the AMERICAN manufacturer carries the exchange-rate risk: if the USD falls against the AUD, the payment costs them more. A derivative protects them from a falling American dollar."}, {"id": "2021-Q20", "year": 2021, "n": 20, "topic": "Operations", "subs": ["Operations strategies"], "img": "2021_Q20.png", "w": 1028, "h": 286, "ans": ["B"], "expl": "Capitalising R&D expenses moves costs off the income statement onto the balance sheet, inflating profit and asset values \u2014 making company B look more valuable than it is. Normalising a one-off sale REMOVES it, lowering apparent earnings."}, {"id": "2022-Q1", "year": 2022, "n": 1, "topic": "Marketing", "subs": ["Influences on marketing"], "img": "2022_Q1.png", "w": 796, "h": 298, "ans": ["B"], "expl": "A recession is an economic factor affecting customer spending. Perception is psychological; regulation is government; subculture is sociocultural."}, {"id": "2022-Q2", "year": 2022, "n": 2, "topic": "Human Resources", "subs": ["Processes of human resource management"], "img": "2022_Q2.png", "w": 888, "h": 298, "ans": ["C"], "expl": "Resignation is the employee's own choice \u2014 voluntary. Dismissal, layoff and retrenchment are all employer-initiated (involuntary)."}, {"id": "2022-Q3", "year": 2022, "n": 3, "topic": "Marketing", "subs": ["Marketing process"], "img": "2022_Q3.png", "w": 825, "h": 299, "ans": ["C"], "expl": "Primary data is gathered first-hand: personal interviews and questionnaires. Industry reports and internet sources are secondary data."}, {"id": "2022-Q4", "year": 2022, "n": 4, "topic": "Marketing", "subs": ["Influences on marketing", "Marketing strategies"], "img": "2022_Q4.png", "w": 1028, "h": 347, "ans": ["B"], "expl": "Price skimming plus a lifetime warranty signals a premium product \u2014 driven by customers' quality expectations. Cost-based competition would push prices down, not up."}, {"id": "2022-Q5", "year": 2022, "n": 5, "topic": "Marketing", "subs": ["Marketing process", "Marketing strategies"], "img": "2022_Q5.png", "w": 1028, "h": 329, "ans": ["D"], "expl": "Lifestyle, motivation and personality are psychographic variables. Demographic uses age/income/gender; behavioural uses usage patterns; geographic uses location."}, {"id": "2022-Q6", "year": 2022, "n": 6, "topic": "Human Resources", "subs": ["Human resource strategies"], "img": "2022_Q6.png", "w": 820, "h": 446, "ans": ["A"], "expl": "Profit sharing is a monetary reward (money-based), and 'all staff participate equally' makes it a group reward \u2014 Monetary + Group."}, {"id": "2022-Q7", "year": 2022, "n": 7, "topic": "Operations", "subs": ["Influences", "Operations processes", "Operations strategies"], "img": "2022_Q7.png", "w": 810, "h": 360, "ans": ["C"], "expl": "Global sourcing \u2014 buying inputs from the cheapest suppliers worldwide \u2014 directly reduces input costs. Training and sustainable packaging typically add cost; product variety adds complexity."}, {"id": "2022-Q8", "year": 2022, "n": 8, "topic": "Human Resources", "subs": [], "img": "2022_Q8.png", "w": 1028, "h": 347, "ans": ["A"], "expl": "Training in the safe use of machinery primarily aims to prevent workplace accidents (WHS obligation). Reduced absenteeism/turnover are secondary benefits."}, {"id": "2022-Q9", "year": 2022, "n": 9, "topic": "Finance", "subs": [], "img": "2022_Q9.png", "w": 818, "h": 360, "ans": ["D"], "expl": "Dispute resolution starts with the least formal step: negotiation directly between the parties. Mediation, conciliation and arbitration involve third parties and come later if talks fail."}, {"id": "2022-Q10", "year": 2022, "n": 10, "topic": "Operations", "subs": ["Influences"], "img": "2022_Q10.png", "w": 1028, "h": 391, "ans": ["D"], "expl": "Chemical use in production is governed by environmental protection legislation \u2014 a legal influence on operations. Codes of conduct are voluntary; superannuation and union membership are HR matters."}, {"id": "2022-Q11", "year": 2022, "n": 11, "topic": "Marketing", "subs": ["Marketing process"], "img": "2022_Q11.png", "w": 948, "h": 385, "ans": ["C", "D"], "expl": "In the growth phase production increases to meet rising demand; price is typically maintained (or may rise as competitors enter with the product established). NESA accepted both 'increased/increased' and 'increased/maintained'."}, {"id": "2022-Q12", "year": 2022, "n": 12, "topic": "Operations", "subs": ["Operations strategies"], "img": "2022_Q12.png", "w": 931, "h": 254, "ans": ["C"], "expl": "Service differentiation is varying the SERVICE experience \u2014 the assistant spending different amounts of time with each customer tailors the service. Tinted windows differentiate a GOOD; receipts and scripts are standard procedure."}, {"id": "2022-Q13", "year": 2022, "n": 13, "topic": "Operations", "subs": ["Influences"], "img": "2022_Q13.png", "w": 1028, "h": 329, "ans": ["C"], "expl": "Expansion is supported by an improved economic outlook (more demand) and LOW interest rates (cheap finance for the expansion). High rates or weak outlooks discourage it."}, {"id": "2022-Q14", "year": 2022, "n": 14, "topic": "Finance", "subs": ["Influences on financial management"], "img": "2022_Q14.png", "w": 1028, "h": 391, "ans": ["D"], "expl": "Misusing client funds breaches the Corporations Act \u2014 enforced by ASIC (Australian Securities and Investments Commission), the corporate regulator. The ATO handles tax; APRA supervises banks and insurers."}, {"id": "2022-Q15", "year": 2022, "n": 15, "topic": "Marketing", "subs": ["Marketing strategies"], "img": "2022_Q15.png", "w": 1028, "h": 391, "ans": ["A"], "expl": "Small-scale excess production sold locally suits the simplest, most direct channel: producer \u2192 consumer (e.g. farm-gate sales). Intermediaries would eat the margin on a small volume."}, {"id": "2022-Q16", "year": 2022, "n": 16, "topic": "Marketing", "subs": [], "img": "2022_Q16.png", "w": 1028, "h": 285, "ans": ["B"], "expl": "Penetration pricing sets a low initial price; the disadvantage is customers anchor to that low price, making later price rises difficult without losing them."}, {"id": "2022-Q17", "year": 2022, "n": 17, "topic": "Marketing", "subs": [], "img": "2022_Q17.png", "w": 710, "h": 360, "ans": ["B"], "expl": "The florist buys flowers as inputs to create a new product (arrangements) \u2014 operating in the industrial market (buying goods for further processing)."}, {"id": "2022-Q18", "year": 2022, "n": 18, "topic": "Finance", "subs": ["Influences on financial management", "Role of financial management"], "img": "2022_Q18.png", "w": 1028, "h": 391, "ans": ["D"], "expl": "Sale and lease-back converts a fixed asset into $2m cash (minus the $500k mortgage payout), boosting current assets \u2014 improving working capital while retaining use of the building."}, {"id": "2022-Q19", "year": 2022, "n": 19, "topic": "Finance", "subs": [], "img": "2022_Q19.png", "w": 1028, "h": 347, "ans": ["C"], "expl": "Outsourcing cake decorations involves: operations (production specs/quality), human resources (impact on existing staff/contractor arrangements) and finance (cost of contract). Marketing isn't directly part of the supply contract."}, {"id": "2022-Q20", "year": 2022, "n": 20, "topic": "Finance", "subs": ["Processes of financial management", "Role of financial management"], "img": "2022_Q20.png", "w": 1028, "h": 919, "ans": ["A"], "expl": "Year 1: GP 400k, NP 150k \u2192 ROE 30%. Year 2: GP 500k, NP 300k \u2192 ROE 60% \u2014 improved. GP ratio year 2 = 500/700 = 71.4%, below the 78% industry average \u2014 worse than industry. So A."}, {"id": "2023-Q1", "year": 2023, "n": 1, "topic": "Human Resources", "subs": ["Human resource strategies"], "img": "2023_Q1.png", "w": 818, "h": 287, "ans": ["B"], "expl": "Rewards aim to recognise and reinforce employees' value and contribution, motivating performance and retention. They aren't legally required, nor primarily about preventing industrial action."}, {"id": "2023-Q2", "year": 2023, "n": 2, "topic": "Operations", "subs": ["Operations strategies"], "img": "2023_Q2.png", "w": 1028, "h": 408, "ans": ["A"], "expl": "Designing displays to each couple's individual preferences is customisation \u2014 making products to individual customer requirements. Flexibility is adjusting to demand changes; quality is meeting standards."}, {"id": "2023-Q3", "year": 2023, "n": 3, "topic": "Marketing", "subs": ["Marketing strategies"], "img": "2023_Q3.png", "w": 762, "h": 287, "ans": ["A"], "expl": "Relationship marketing builds long-term customer loyalty through ongoing relationships (loyalty programs, personalised contact). One-off promotions boost short-term sales instead."}, {"id": "2023-Q4", "year": 2023, "n": 4, "topic": "Human Resources", "subs": ["Human resource strategies", "Processes of human resource management"], "img": "2023_Q4.png", "w": 1028, "h": 342, "ans": ["C"], "expl": "An employee injured at work is entitled to workers compensation \u2014 covering medical costs and lost wages during recovery."}, {"id": "2023-Q5", "year": 2023, "n": 5, "topic": "Marketing", "subs": ["Marketing strategies"], "img": "2023_Q5.png", "w": 854, "h": 360, "ans": ["C"], "expl": "Penetration pricing sets a low initial price to quickly capture a large market share. Skimming does the opposite \u2014 high price, small volume, high margin."}, {"id": "2023-Q6", "year": 2023, "n": 6, "topic": "Operations", "subs": [], "img": "2023_Q6.png", "w": 1028, "h": 391, "ans": ["A"], "expl": "Reduced working hours due to falling DEMAND reflects the economic cycle \u2014 an economic influence on human resources."}, {"id": "2023-Q7", "year": 2023, "n": 7, "topic": "Marketing", "subs": ["Marketing process"], "img": "2023_Q7.png", "w": 1028, "h": 422, "ans": ["D"], "expl": "The marketing plan begins with a situational analysis (where are we?), then market research, then establishing objectives, then identifying target markets \u2014 option D's order."}, {"id": "2023-Q8", "year": 2023, "n": 8, "topic": "Finance", "subs": ["Influences on financial management"], "img": "2023_Q8.png", "w": 981, "h": 316, "ans": ["D"], "expl": "Payment in advance means the exporter receives the money BEFORE shipping \u2014 zero risk of non-payment. Letters of credit are safe but still involve bank/timing risk; clean payment is riskiest."}, {"id": "2023-Q9", "year": 2023, "n": 9, "topic": "Operations", "subs": ["Role of operations management"], "img": "2023_Q9.png", "w": 1028, "h": 329, "ans": ["D"], "expl": "Training staff (human resources) in the manufacturing process (operations) shows operations and human resources working interdependently."}, {"id": "2023-Q10", "year": 2023, "n": 10, "topic": "Marketing", "subs": ["Marketing strategies"], "img": "2023_Q10.png", "w": 869, "h": 361, "ans": ["B"], "expl": "A celebrity promoting products is an opinion leader \u2014 someone whose views influence others' purchasing decisions. Personal selling is direct salesperson-to-customer contact."}, {"id": "2023-Q11", "year": 2023, "n": 11, "topic": "Human Resources", "subs": ["Human resource strategies"], "img": "2023_Q11.png", "w": 1028, "h": 329, "ans": ["A"], "expl": "The Fair Work Commission is Australia's workplace tribunal: it approves enterprise agreements, sets awards and resolves workplace disputes. The AHRC handles discrimination; ASIC regulates companies."}, {"id": "2023-Q12", "year": 2023, "n": 12, "topic": "Finance", "subs": ["Financial management strategies", "Influences on financial management"], "img": "2023_Q12.png", "w": 1028, "h": 347, "ans": ["C"], "expl": "Leasing spreads the $185,000 cost over the asset's life without a large upfront outlay \u2014 appropriate long-term finance for equipment. An overdraft is short-term; hedging and derivatives manage risk, they don't fund purchases."}, {"id": "2023-Q13", "year": 2023, "n": 13, "topic": "Marketing", "subs": ["Influences on marketing", "Marketing strategies"], "img": "2023_Q13.png", "w": 1028, "h": 422, "ans": ["B"], "expl": "Consumer law implies conditions into every contract of sale \u2014 goods must be of merchantable quality and fit for purpose. A faulty phone breaches these implied conditions, so a refund is required by law, not just ethics."}, {"id": "2023-Q14", "year": 2023, "n": 14, "topic": "Finance", "subs": ["Influences on financial management"], "img": "2023_Q14.png", "w": 1028, "h": 474, "ans": ["B"], "expl": "A stronger AUD (0.50 \u2192 0.70 USD) makes imports cheaper for Australians (each AUD buys more) and Australian exports more expensive for US buyers \u2014 Less expensive / More expensive."}, {"id": "2023-Q15", "year": 2023, "n": 15, "topic": "Operations", "subs": ["Operations strategies", "Role of operations management"], "img": "2023_Q15.png", "w": 1028, "h": 346, "ans": ["D"], "expl": "Focusing operations on design and innovation creates products that stand out \u2014 goods/services differentiation. Cost leadership competes on price, not design."}, {"id": "2023-Q16", "year": 2023, "n": 16, "topic": "Operations", "subs": ["Operations processes", "Operations strategies"], "img": "2023_Q16.png", "w": 1028, "h": 1211, "ans": ["B"], "expl": "Net profit = 100,000 \u2212 40,000 = 60,000. Net profit ratio = 60,000 \u00f7 300,000 = 20%."}, {"id": "2023-Q17", "year": 2023, "n": 17, "topic": "Operations", "subs": ["Operations processes"], "img": "2023_Q17.png", "w": 907, "h": 817, "ans": ["C"], "expl": "After task B, three branches leave the same node: BE, BF and BC can all run simultaneously because none depends on another finishing first."}, {"id": "2023-Q18", "year": 2023, "n": 18, "topic": "Operations", "subs": ["Operations processes", "Operations strategies"], "img": "2023_Q18.png", "w": 907, "h": 923, "ans": ["B"], "expl": "Original critical path runs 18 days. EC delayed by 7 days makes its path 20 days, which exceeds the old critical path by 2 \u2014 the project lengthens by 2 days."}, {"id": "2023-Q19", "year": 2023, "n": 19, "topic": "Human Resources", "subs": ["Key influences"], "img": "2023_Q19.png", "w": 1028, "h": 330, "ans": ["D"], "expl": "Only government organisations have the POWER to legislate workplace reforms (e.g. anti-discrimination and equal opportunity laws). Unions advocate but cannot implement laws."}, {"id": "2023-Q20", "year": 2023, "n": 20, "topic": "Finance", "subs": ["Influences on financial management", "Processes of financial management"], "img": "2023_Q20.png", "w": 1028, "h": 830, "ans": ["A", "D"], "expl": "Current ratio = 59,000 \u00f7 43,400 \u2248 1.36:1. Selling excess machinery (non-current) converts it to cash (current asset), raising the ratio. NESA also accepted early-payment discounts (speeds cash collection). New borrowing/mortgages worsen or don't help the ratio."}, {"id": "2024-Q1", "year": 2024, "n": 1, "topic": "Human Resources", "subs": ["Key influences"], "img": "2024_Q1.png", "w": 824, "h": 299, "ans": ["A"], "expl": "Trade unions represent employees in negotiations for wages and conditions. Employer associations represent businesses; the courts and FWA adjudicate rather than represent."}, {"id": "2024-Q2", "year": 2024, "n": 2, "topic": "Operations", "subs": ["Influences", "Operations strategies"], "img": "2024_Q2.png", "w": 720, "h": 298, "ans": ["C"], "expl": "Banning dangerous goods like asbestos comes from legal regulations \u2014 government laws controlling what businesses can produce and use."}, {"id": "2024-Q3", "year": 2024, "n": 3, "topic": "Human Resources", "subs": ["Processes of human resource management"], "img": "2024_Q3.png", "w": 1028, "h": 329, "ans": ["B"], "expl": "Performance appraisals occur in the development stage \u2014 reviewing performance to identify training needs and career growth. Acquisition is hiring; separation is departure."}, {"id": "2024-Q4", "year": 2024, "n": 4, "topic": "Marketing", "subs": ["Influences on marketing", "Marketing strategies"], "img": "2024_Q4.png", "w": 1028, "h": 346, "ans": ["A"], "expl": "A significantly higher price for a NEW product during its first period on sale is price skimming \u2014 capturing early adopters willing to pay a premium before lowering price."}, {"id": "2024-Q5", "year": 2024, "n": 5, "topic": "Marketing", "subs": ["Marketing strategies"], "img": "2024_Q5.png", "w": 986, "h": 387, "ans": ["C"], "expl": "Effective HR management improves safety and engagement \u2014 workplace accidents DECREASE and absenteeism DECREASES."}, {"id": "2024-Q6", "year": 2024, "n": 6, "topic": "Finance", "subs": [], "img": "2024_Q6.png", "w": 1028, "h": 391, "ans": ["D"], "expl": "A tax benefit tied to renewable energy is a government incentive to encourage environmentally sustainable business behaviour \u2014 policy steering conduct through the tax system."}, {"id": "2024-Q7", "year": 2024, "n": 7, "topic": "Human Resources", "subs": [], "img": "2024_Q7.png", "w": 1028, "h": 391, "ans": ["C"], "expl": "Physiotherapy treatment is a service (intangible, produced and consumed simultaneously) and it's tailored to the individual injury \u2014 a customised service."}, {"id": "2024-Q8", "year": 2024, "n": 8, "topic": "Human Resources", "subs": ["Processes of human resource management"], "img": "2024_Q8.png", "w": 1028, "h": 316, "ans": ["B"], "expl": "Being told to leave because of misconduct is dismissal. Retrenchment/redundancy occur when the job disappears; attrition is natural workforce reduction through resignations/retirements."}, {"id": "2024-Q9", "year": 2024, "n": 9, "topic": "Operations", "subs": ["Operations strategies"], "img": "2024_Q9.png", "w": 683, "h": 298, "ans": ["A"], "expl": "The operations manager's role centres on efficiency: maximising outputs from inputs and reducing waste \u2014 'reduce waste and increase efficiency'."}, {"id": "2024-Q10", "year": 2024, "n": 10, "topic": "Finance", "subs": ["Processes of financial management"], "img": "2024_Q10.png", "w": 789, "h": 644, "ans": ["D"], "expl": "Expenses = gross profit \u2212 net profit = 600,000 \u2212 250,000 = 350,000. Expense ratio = 350,000 \u00f7 800,000 = 43.75% \u2248 44%."}, {"id": "2024-Q11", "year": 2024, "n": 11, "topic": "Marketing", "subs": ["Marketing strategies"], "img": "2024_Q11.png", "w": 1028, "h": 378, "ans": ["A"], "expl": "Surveying shoppers, then using the survey as a springboard to sell \u2014 selling under the guise of research \u2014 is sugging. Legal, but ethically questionable."}, {"id": "2024-Q12", "year": 2024, "n": 12, "topic": "Operations", "subs": ["Influences"], "img": "2024_Q12.png", "w": 1028, "h": 391, "ans": ["B"], "expl": "A senior overseas management role suits an individual (common law) contract negotiated one-on-one, covering tailored salary and conditions. Collective/greenfields agreements cover groups of employees."}, {"id": "2024-Q13", "year": 2024, "n": 13, "topic": "Marketing", "subs": ["Influences on marketing"], "img": "2024_Q13.png", "w": 1028, "h": 422, "ans": ["D"], "expl": "Customers ASSUME the product is inferior because of the brand name \u2014 a perception, which is a psychological factor influencing consumer choice."}, {"id": "2024-Q14", "year": 2024, "n": 14, "topic": "Finance", "subs": [], "img": "2024_Q14.png", "w": 866, "h": 553, "ans": ["C"], "expl": "Jul close: 40+30\u221220 = 50. Aug: 50+10\u221213 = 47. Sep: 47+22\u221215 = $54,000."}, {"id": "2024-Q15", "year": 2024, "n": 15, "topic": "Finance", "subs": ["Influences on financial management"], "img": "2024_Q15.png", "w": 1028, "h": 329, "ans": ["B"], "expl": "The ASX (Australian Securities Exchange) operates the market where companies list and raise public equity finance. ASIC regulates conduct; it doesn't operate the market."}, {"id": "2024-Q16", "year": 2024, "n": 16, "topic": "Marketing", "subs": ["Marketing strategies"], "img": "2024_Q16.png", "w": 1028, "h": 391, "ans": ["B"], "expl": "One identical marketing mix across countries is standardisation \u2014 its key advantage is economies of scale (one campaign, one set of materials, lower average costs). Customisation is the opposing approach."}, {"id": "2024-Q17", "year": 2024, "n": 17, "topic": "Finance", "subs": ["Processes of financial management"], "img": "2024_Q17.png", "w": 838, "h": 360, "ans": ["D"], "expl": "To inflate the sale price, an unethical seller would overstate income and understate expenses \u2014 making profit look bigger. Undervaluing assets or overstating expenses would LOWER the apparent value."}, {"id": "2024-Q18", "year": 2024, "n": 18, "topic": "Operations", "subs": ["Operations processes", "Operations strategies"], "img": "2024_Q18.png", "w": 1028, "h": 285, "ans": ["B"], "expl": "Critical path analysis maps what tasks are needed, how long each takes, and the necessary order (dependencies). It doesn't address quality testing or component counts."}, {"id": "2024-Q19", "year": 2024, "n": 19, "topic": "Finance", "subs": ["Influences on financial management"], "img": "2024_Q19.png", "w": 1028, "h": 391, "ans": ["C"], "expl": "Going from private to publicly listed and issuing shares to the public for the first time is a new issue (float/IPO) \u2014 equity finance from new shareholders."}, {"id": "2024-Q20", "year": 2024, "n": 20, "topic": "Marketing", "subs": ["Marketing strategies"], "img": "2024_Q20.png", "w": 1028, "h": 535, "ans": ["D"], "expl": "The objective is market DOMINANCE, but share fell from 20% to 15% despite doubled advertising \u2014 so the manager must review and control the whole marketing mix, not just spend more on one element."}, {"id": "2025-Q1", "year": 2025, "n": 1, "topic": "Operations", "subs": ["Operations processes", "Operations strategies"], "img": "2025_Q1.png", "w": 1028, "h": 321, "ans": ["A"], "expl": "Minimising waste in production reduces the cost per unit \u2014 the cost performance objective. Speed relates to time, flexibility to adapting."}, {"id": "2025-Q2", "year": 2025, "n": 2, "topic": "Operations", "subs": [], "img": "2025_Q2.png", "w": 946, "h": 351, "ans": ["B"], "expl": "Customised caravans with solar panels serve a small, specialised segment of caravan buyers \u2014 a niche market within the broader market."}, {"id": "2025-Q3", "year": 2025, "n": 3, "topic": "Finance", "subs": ["Processes of financial management"], "img": "2025_Q3.png", "w": 831, "h": 289, "ans": ["A"], "expl": "A balance sheet shows assets, liabilities and owner's equity at a point in time. Sales, expenses and wages belong to the income statement."}, {"id": "2025-Q4", "year": 2025, "n": 4, "topic": "Human Resources", "subs": [], "img": "2025_Q4.png", "w": 1028, "h": 346, "ans": ["D"], "expl": "Disadvantaging an employee because of pregnancy/maternity leave is sex discrimination \u2014 prohibited by the Sex Discrimination Act 1984 (Cth)."}, {"id": "2025-Q5", "year": 2025, "n": 5, "topic": "Marketing", "subs": ["Influences on marketing", "Marketing strategies"], "img": "2025_Q5.png", "w": 1028, "h": 391, "ans": ["D"], "expl": "Advertising a normal price as a 'special' misleads customers about the saving \u2014 deceptive and misleading advertising, prohibited under the Australian Consumer Law."}, {"id": "2025-Q6", "year": 2025, "n": 6, "topic": "Marketing", "subs": ["Marketing strategies"], "img": "2025_Q6.png", "w": 1028, "h": 391, "ans": ["A"], "expl": "Adapting designs and advertising to Japanese trends and cultural preferences is customisation \u2014 tailoring the marketing mix to the local market. Standardisation would use identical products/ads everywhere."}, {"id": "2025-Q7", "year": 2025, "n": 7, "topic": "Operations", "subs": ["Operations strategies"], "img": "2025_Q7.png", "w": 716, "h": 298, "ans": ["C"], "expl": "Logistics is the physical distribution function: transport, storage, and materials handling and packaging. Plant layout and quality checks belong to other operations areas."}, {"id": "2025-Q8", "year": 2025, "n": 8, "topic": "Operations", "subs": ["Operations strategies"], "img": "2025_Q8.png", "w": 1028, "h": 346, "ans": ["D"], "expl": "An ongoing commitment to becoming more efficient and effective is continuous improvement \u2014 the 'improvement' approach within quality management. Control checks output; assurance follows set standards."}, {"id": "2025-Q9", "year": 2025, "n": 9, "topic": "Finance", "subs": ["Role of financial management"], "img": "2025_Q9.png", "w": 1028, "h": 391, "ans": ["A"], "expl": "Collecting receivables faster than the credit terms (26 vs 30 days) shows efficient use of resources \u2014 the financial objective of efficiency."}, {"id": "2025-Q10", "year": 2025, "n": 10, "topic": "Human Resources", "subs": ["Key influences"], "img": "2025_Q10.png", "w": 1028, "h": 329, "ans": ["D"], "expl": "The legal framework for HR includes common law (employment contracts/duties), minimum employment standards (NES) and workers compensation legislation. Codes of conduct are internal policy, not law."}, {"id": "2025-Q11", "year": 2025, "n": 11, "topic": "Human Resources", "subs": ["Human resource strategies"], "img": "2025_Q11.png", "w": 960, "h": 298, "ans": ["B"], "expl": "Internal recruitment motivates existing staff \u2014 promotion opportunities encourage professional growth and retention. Larger applicant pools and outside perspectives are benefits of EXTERNAL recruitment."}, {"id": "2025-Q12", "year": 2025, "n": 12, "topic": "Operations", "subs": ["Influences", "Operations strategies"], "img": "2025_Q12.png", "w": 1028, "h": 347, "ans": ["A"], "expl": "Employees most commonly resist new technology from fear of the unknown \u2014 uncertainty about their jobs and ability to adapt. Redundancy payments and costs concern the employer, not resisting staff."}, {"id": "2025-Q13", "year": 2025, "n": 13, "topic": "Marketing", "subs": ["Marketing process"], "img": "2025_Q13.png", "w": 1028, "h": 391, "ans": ["B"], "expl": "Recognising that poor customer service has hurt sales is identifying a weakness \u2014 part of the situational analysis (SWOT) stage of the marketing process."}, {"id": "2025-Q14", "year": 2025, "n": 14, "topic": "Marketing", "subs": [], "img": "2025_Q14.png", "w": 1028, "h": 329, "ans": ["C"], "expl": "A discounted first month attracts trial while keeping the ongoing price sustainable. High introductory prices deter new customers; below-cost lifetime memberships aren't viable."}, {"id": "2025-Q15", "year": 2025, "n": 15, "topic": "Human Resources", "subs": ["Key influences"], "img": "2025_Q15.png", "w": 979, "h": 782, "ans": ["C"], "expl": "After month 3, performance falls while stress and absenteeism climb together \u2014 a pattern pointing to a change in senior management (e.g. new leadership style). The other options would IMPROVE the indicators."}, {"id": "2025-Q16", "year": 2025, "n": 16, "topic": "Finance", "subs": ["Financial management strategies"], "img": "2025_Q16.png", "w": 1000, "h": 730, "ans": ["A", "B"], "expl": "The closing balance first turns negative after August/September's cash-out exceeds cash-in (Aug: \u22122,000, Sep: \u22124,000 cumulative) \u2014 strategies were needed then, before the deficit deepened. NESA accepted August and September."}, {"id": "2025-Q17", "year": 2025, "n": 17, "topic": "Marketing", "subs": ["Marketing strategies"], "img": "2025_Q17.png", "w": 909, "h": 483, "ans": ["C"], "expl": "Correct WHS/injury management sequence: assess the work site for safety, create an injury management plan, then assign suitable (light) duties for return to work. Annual leave is not part of injury management."}, {"id": "2025-Q18", "year": 2025, "n": 18, "topic": "Finance", "subs": ["Processes of financial management"], "img": "2025_Q18.png", "w": 1028, "h": 391, "ans": ["D"], "expl": "Recording $2bn of R&D spending on the balance sheet treats an expense as an asset \u2014 capitalising expenses, which overstates assets and profit."}, {"id": "2025-Q19", "year": 2025, "n": 19, "topic": "Operations", "subs": ["Operations processes"], "img": "2025_Q19.png", "w": 877, "h": 360, "ans": ["B"], "expl": "The operations process flows inputs \u2192 transformation \u2192 outputs: facilities (transforming resource/input) \u2192 control (part of transformation) \u2192 customer service (output stage). The other options jumble the sequence."}, {"id": "2025-Q20", "year": 2025, "n": 20, "topic": "Finance", "subs": ["Processes of financial management", "Role of financial management"], "img": "2025_Q20.png", "w": 877, "h": 475, "ans": ["A"], "expl": "Gearing fell from 75% to 66% \u2014 lower debt relative to equity means the debt-to-equity ratio has IMPROVED: less risk, better solvency. Lower gearing typically means lower (not higher) return on equity leverage."}];
const SYLLABUS = {"Operations": ["Role of operations management", "Influences", "Operations processes", "Operations strategies"], "Marketing": ["Role of marketing", "Influences on marketing", "Marketing process", "Marketing strategies"], "Finance": ["Role of financial management", "Influences on financial management", "Processes of financial management", "Financial management strategies"], "Human Resources": ["Role of human resource management", "Key influences", "Processes of human resource management", "Human resource strategies"]};
